INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (8, '33614287', 1190000.0, 840.0, 26, 6, 'Casale/cascina in Case sparse, 34', '� Farmhouse for sale in Tuscany" perfectly restored country house in Chianti Classico� In the heart of Chianti Classico, among golden vineyards and medieval villages, stands a perfectly restored Tuscan farmhouse, a living testimony to seven centuries of history. Anyone looking for a property for sale in Italy will find here not only an authentic Tuscan experience but also the potential for a secure and appreciable investment, thanks to the professional support in restoration and heritage care offered by Gruppo Manini.� A journey through time in the heart of TuscanyIn one of the most iconic corners of the region, where sun-kissed hills form a mosaic of vineyards and forests, this property tells an ancient story: once a 13th-century watchtower, later transformed into a 16th-century mill serving the nearby castle, today it shines as a luxury residence already operating as a high-end holiday rental. Here, among cypresses and winding country roads, time slows down, offering a setting of rare beauty and peace.�️ The main residence" 500 sqm of rustic eleganceSpread over three levels and currently arranged as three independent apartments (easily reconnected into a single home), the main house offers bright interiors and authentic Tuscan character Ground floor: a charming loggia entrance opens onto a living room with fireplace, created from the old stables. Beyond lie the dining area, a characterful Tuscan kitchen, and a second independent kitchen, perfect for guests or separate use.- First floor: a spacious living area with fireplace and panoramic loggia with breathtaking views. This level hosts five bedrooms and five bathrooms (two en-suite).- Medieval tower: at the top, a sixth bedroom with private bathroom serves as a romantic retreat and privileged viewpoint over Tuscan sunsets.� Outbuildings and expansion potential145 sqm barn: ideal for conversion into an exclusive guest house, private spa, or artist''s studio.96 sqm former stables (currently storage): perfect for crea', 'Gaiole in Chianti', 'Siena', 'toscana', 'Case sparse, 34', 43.4509856, 11.4450721, 'https://www.idealista.it/immobile/33614287/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/da/b7/0e/724229538.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/da/b7/0e/724229538.webp"]', 43, 'casalicascine', 'casale', 78.0, 86.0, 40.0, 80.0, 93.0, 64.0, 84.0, 1417.0, 'Firenze (FLR)', 44.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (9, '33115915', 300000.0, 500.0, 8, 1, 'Casale/cascina in Zona D, 38', '"Masseria Gemma Bella" is a typical farmhouse in the Apulian territory, located in Noci (Province of Bari) in the Murgia Park, 18km-20mn from Alberobello. The ancient historical and partly modern residence consists of 4 INDEPENDENT NUCLEI with a total covered area of 400 square meters (total walkable area 300 square meters, TO BE RENOVATED, surrounded by 2,000 SQM WITH GARDEN AND AN "ANCIENT COURTYARD" TO ADD 4 HECTARES OF PASTURE OLIVE GROVE AND WOODLAND NOT INCLUDED IN THE PRICE. The location is enchanting, an ideal oasis of tranquility for those looking for great privacy in an area of unique scenic beauty, located in a SIC (Site of Community Interest) area thanks to its particular naturalistic characteristics of Mediterranean flora and fauna. In the heart of Puglia, it is strategic for reaching the urban center of Noci and all the most sought after and well-known places nearby (Alberobello, Valle d''Itria, cities and beaches of the Adriatic Sea...Matera) in a few minutes. The property consists of a manor house on the ground floor, consisting of a living area of approximately 120 square meters and a veranda outside, plus an area of approximately 240 square meters in which there are: stables, barns, various deposits with a large "courtyard". The adjoining land occupies an area of 2,000 square meters to add four and a half hectares, including pasture and arable land not included, and the possibility of building a swimming pool next to and at the level of the courtyard. Each housing unit is autonomous and with an independent entrance. They overlook an ancient "courtyard" paved in local stone of approximately 140 square meters and a natural garden. The outdoor spaces also include ample parking, all surrounded by dry stone walls and a 2000 square meter garden. The large outdoor spaces include a spacious garden to create a gazebo with a splendid view of the valley, a large paved courtyard (including the ancient courtyard) and the possibility of building a swimming pool. ', 'Noci', 'Bari', 'puglia', 'Zona D, 38', 40.793902, 17.1258599, 'https://www.idealista.it/immobile/33115915/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/09/e0/de/711211194.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/09/e0/de/711211194.webp"]', 30, 'casalicascine', 'masseria', 76.0, 100.0, 40.0, 80.0, 60.0, 74.0, 86.0, 600.0, 'Bari (BRI)', 49.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (10, '34648720', 1690000.0, 1570.0, 38, 8, 'Casale/cascina in località Portole, 39', 'Country house with outbuildings totaling 1,570 sqm, Land and pool in Cortona Description The property, used as an agritourism with a restaurant, is divided into various buildings. The main building houses the main apartment of 292 sqm over two levels. On the ground floor, there is a restaurant space of about 110 sqm overlooking the terrace, as well as approximately 370 sqm of unfinished volumes to be restored, plus 95 sqm of cellars and technical rooms, and 104 sqm of attics. The second building includes an apartment of about 109 sqm for guests. The third building comprises a workshop on the ground floor of about 98 sqm divided into three rooms and 48 sqm of technical rooms, and on the first floor, a 108 sqm apartment. There are also detached volumes such as a business shop of about 32 sqm and a 189 sqm barn to be renovated. State and Finishes The renovated part of the property features top-level finishes with typical materials and modern elements, bright spaces and delicate colors, along with restored wooden fixtures and doors. The systems are highly efficient, with a wood boiler. The areas to be completed require only finishing works and systems installation, as the structural part is excellent. External Spaces The property has about 68 hectares of total land, mostly wooded but also including arable land, a small vineyard, pastures, and a fruit orchard. There is also a pool of about 40 sqm with an octagonal shape. The garden extends all in front of the property. Potential Uses The property can be used for various purposes, from continuing agricultural tourism activities to serving as a holiday home or private residence for short-term rentals. Location and Lifestyle Situated in a panoramic position about 15 minutes from the center of Cortona, with stunning views of Lake Trasimeno and the hills, this historic property enjoys privacy without sacrificing daily comfort. It is 10/15 minutes from Camucia and the historic center of Cortona for all necessary services. Abou', 'Cortona', 'Arezzo', 'toscana', 'località Portole, 39', 43.2996466, 12.0429125, 'https://www.idealista.it/immobile/34648720/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/63/ca/08/763821368.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/63/ca/08/763821368.webp"]', 37, 'casalicascine', 'casale', 76.0, 100.0, 40.0, 60.0, 84.0, 66.0, 77.0, 1076.0, 'Firenze (FLR)', 88.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (11, '33609676', 415000.0, 390.0, 10, 3, 'Villa in vicolo Botteghino, 56033', 'CAPANNOLI – Portion of VILLA (province of Pisa) Prestigious portion of an ancient historic building in the heart of the center – Our Exclusive In the heart of Capannoli, we offer for sale a historic villa of great charm, developed on two main levels plus attic and cellars, for over 400 square meters overall. distributed on two main levels, with attic and large cellars and equipped with garden and private courtyard with exclusive parking spaces. Access to the villa is from the garden and private courtyard of approximately 470 square meters, which can be reached from the P.zza del Popolo via a driveway gate and shared avenue. Architectural features The house retains the intact charm of Tuscan noble residences, renovated years ago while maintaining the original materials and characteristics of the building: •frescoed ceilings or with exposed beams and rafters, •large bright rooms, •original terracotta and cement tile floors. •suggestive underground cellars, used as storage (ideal for creating tasting places, service spaces or characteristic environments). Needs some modernization work on the systems. Internal distribution •Ground floor (approx. 195 sq m): large and impressive entrance-living room, large very bright eat-in kitchen with fireplace, representative lounge with vaulted ceilings, large bedroom, hallway, bathroom and service room (laundry/ironing etc.). •First floor (approx. 195 sq m): elegant hallway, large living room, 5 bedrooms and two bathrooms. •Attic: large attic accessible by internal staircase, used as storage. •Cellars: charming rooms, with access also from a "secret" internal staircase. A strategic position The villa is located in the province of Pisa, in the heart of the Tuscan hills of Valdera, in a central but private position. •Only 25 km from Pisa, 35 km from Lucca, 50 km from Florence and 40 km from Volterra, all easily reachable. •Services, shops, schools and public transport are available within walking distance, making the property convenie', 'Capannoli', 'Pisa', 'toscana', 'vicolo Botteghino, 56033', 43.5840389, 10.6784205, 'https://www.idealista.it/immobile/33609676/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/31/c5/14/724098895.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/31/c5/14/724098895.webp"]', 69, 'villa', 'villa', 76.0, 100.0, 40.0, 100.0, 64.0, 74.0, 76.0, 1064.0, 'Pisa (PSA)', 26.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (12, '34121964', 370000.0, 332.0, 9, 4, 'Detached house', 'Large detached villa offering bright and spacious accomodation, with land, garage and beautiful views. Presented in excellent condition, the property has the advantage of additional spaces - garage, workshop with bathroom, large storage room - for work or recreation, and ample sunny, south-west facing land with space for a swimming pool (subject to planning permission). The villa offers total peace and privacy, yet is just a 5 minute drive from Chianni.  The accommodation (250 sqm) is over two levels and comprises: on the ground floor, entrance hall, living room, kitchen opening to balcony with panoramic views and space for al fresco dining, large storage room with a window, two bathrooms and three bedrooms. The basement level has a taverna used for dining and cooking of around 100 sqm, with fireplace and accessed via a spiral staircase from the living room, or directly from the garden; there is also a bathroom and store room on this level. Next to the taverna there is a garage (50 sqm), currently used as a workshop. On the ground floor at the rear of the house, there is also a separate spacious storage room of 50 sqm with bathroom and shower room; an excellent space for a hobby room. The heating system is mains gas (metano) and radiators, plus there is a fireplace in the kitchen and also in the taverna. The house is equipped with fly screens, double-glazed windows and solid wooden shutters. Located just 5 minutes from the village centre, this villa offers a strategic position between privacy and convenience, with a southwest-facing garden / land (2,360 sq m / 0,59 acres) that is very bright, favouring afternoon light and peaceful outdoor hours.  Utilites are connected and systems are in good working order; the property is ready to be lived in. Chianni is a lovely town in Tuscany with some nice shops, good coffee bars, a great new bistro and a lovely hotel with small spa (open to non-residents) which is all just a very short stroll away. It is just 40 mins from Pisa', 'Chianni', 'Pisa', 'toscana', 'Chianni', 43.4860544, 10.6423519, 'https://www.idealista.it/immobile/34121964/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f7/6a/c6/742319232.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f7/6a/c6/742319232.webp"]', 46, 'independantHouse', 'villa', 76.0, 99.0, 40.0, 100.0, 64.0, 72.0, 79.0, 1114.0, 'Pisa (PSA)', 30.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (13, '33157122', 150000.0, 320.0, 8, NULL, 'Casale/cascina in frazione Villa, 8', 'Independent country house with garden in Serravalle Langhe In a dominant position, immersed in the unique landscape of the Langhe, an enchanting independent country house, surrounded by a large flat plot of land, perfectly usable for any need. The living area is spread over two levels and is completely to be renovated, offering generous and well-distributed spaces. Adjacent to the main house is the former stable with overlying barn, also of considerable size: ideal environments to expand the residential area or create a tourist-accommodation facility. Thanks to the size and layout of the spaces, this property is suitable both as a home for a large family and as an investment for those wishing to start a business in the Langhe. The land surrounding the property is completely flat, with excellent exposure and easily adaptable to multiple uses, such as a garden, vegetable garden, relaxation area with swimming pool or spaces for animals. A rare and fascinating solution for those who want to live in the quiet and beauty of the Langhe landscape, without sacrificing comfort, privacy and proximity to the main centers of the area. The Dotta real estate agency has stood out for years in the territorial panorama thanks to the extreme seriousness and competence of the staff. It is part of our mission to accompany the client in the process of evaluating and choosing the property that best suits their expectations and needs. Contact us now to view this house in the Langhe together. We will be happy to accompany you to the property without any obligation, with courtesy and professionalism.', 'Serravalle Langhe', 'Cuneo', 'piemonte', 'frazione Villa, 8', 44.5538769, 8.0764909, 'https://www.idealista.it/immobile/33157122/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/48/c0/15/707713868.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/48/c0/15/707713868.webp"]', 33, 'casalicascine', 'casale', 76.0, 100.0, 15.0, 60.0, 92.0, 64.0, 87.0, 469.0, 'Genova (GOA)', 62.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (14, '33831467', 2600000.0, 1618.0, 20, 9, 'Castle in piazza Dante Alighieri', 'TUSCANY | CHIANTI | Ancient Castle immersed in the context of a historic village inhabited by artists. In the heart of Chianti Classico, on the outskirts of a medieval village between Gaiole and Radda in Chianti, stands a castle steeped in centuries of history and tradition. Majestic and timeless, this extraordinary property embodies the essence of Tuscany, combining architectural charm, breathtaking views, and modern comforts. With a surface area of approximately 1,300 square meters, the estate is divided into four main buildings: The Castle – the focal point of the property, rich in historical character. The former Canonica – now deconsecrated and transformed into an art studio, with ceilings soaring 7 meters high. The Dependence – which offers privacy and comfort to guests. The Garage – which combines functionality and practicality. In total, the residence features seven bedrooms, each with a private bathroom, for a total of nine bathrooms, making it perfect both as a private home and for hosting guests. The property extends over 3 hectares of land, with a refined garden and a lush olive grove – an authentic emblem of Tuscan tradition. Every corner offers suggestive glimpses, where hills, vineyards, and timeless countryside blend into a constantly changing tableau of lights and colors. Among the strengths of the property is the panoramic terrace that crowns the castle tower, from which spectacular views of the entire Chianti valley can be admired. Another gem is the pool, harmoniously embedded in the rock, offering a tranquil retreat immersed in nature. This castle is much more than a residence – it represents a rare opportunity to experience the elegance, peace, and prestige of Tuscany, in one of the most fascinating and sought-after locations in the world. DETAILS Garden: 5,000 sqm Land: 3 hectares Pool Private well / connection to the public aqueduct Direct access to methane Solar panels for hot water WWW. MARINELLACOPPISTUDI. COM IN COMPLIANCE WITH PRIVACY RE', 'Radda in Chianti', 'Siena', 'toscana', 'piazza Dante Alighieri', 43.4852662, 11.3739665, 'https://www.idealista.it/immobile/33831467/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/81/63/86/780264088.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/81/63/86/780264088.webp"]', 55, 'castillo', 'villa', 74.0, 77.0, 40.0, 80.0, 93.0, 66.0, 77.0, 1607.0, 'Firenze (FLR)', 39.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (15, '32156771', 240000.0, 262.0, 11, 2, 'Casale/cascina in Pieve di chiò, 9', 'Castiglion Fiorentino, Val di Chio La Casa del Contadino, located in the characteristic village of Pieve di Chio, in the heart of the splendid Val di Chio, among the rolling hills of the Castiglionese countryside, stands this charming 18th-century farmhouse, a true oasis of peace and beauty, perfect for those who dream of living immersed in nature without sacrificing comfort. Located a few kilometers from the historic center of Castiglion Fiorentino, this 240 sq m farmhouse with a garden is the ideal place for those who want a country house, a holiday retreat or an investment in the heart of Tuscany. An authentically charming farmhouse that will welcome you with a warm and evocative atmosphere thanks to its stone facade, terracotta floors and large fireplace that enhance the history and character of the house. On the ground floor there are four large cellars, one with the original animal feed trough and sandstone floors characteristic of the rural areas of the Tuscan countryside, which open onto the exclusive courtyard. Through a characteristic stone staircase we access the living area designed for relaxation and conviviality where we find: a cozy living room with an original fireplace, a kitchen with a dining area, perfect for dinners with friends and family. A bedroom, a bathroom and a multi-purpose room complete the floor. Going up to the first floor, we find a large study, two double bedrooms and a bathroom. Outside, the garden still retains the natural characteristics of a farmhouse courtyard. A perfect place to enjoy the sun, organize outdoor lunches and live in contact with nature without being isolated.', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'Pieve di chiò, 9', 43.3498798, 11.9896423, 'https://www.idealista.it/immobile/32156771/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/c8/19/d3/676301530.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/c8/19/d3/676301530.webp"]', 36, 'casalicascine', 'casale', 74.0, 100.0, 40.0, 60.0, 72.0, 67.0, 78.0, 916.0, 'Firenze (FLR)', 81.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (16, '33193777', 150000.0, 130.0, 6, 1, 'Semi-detached house', 'Lovely stone house, a portion of a building from ground to roof, with independent entrance, tucked-away in a quiet alley in the historic centre of Monteguidi. Included in the price is a convenient garage about 150 metres from the house.  Monteguidi is a tiny village unknown to many but the cradle of the love between Mara and Bebo in the famous book of 1960 “La Ragazza di Bube” by Carlo Cassola; now a pretty village with a breathtaking view over Val d''Elsa and Val di Cecina. The property comprises: private access door and a cellar on the ground floor; on the first floor, kitchen and living room; on the second floor bedroom 1 and bathroom; on the third floor bedroom 2, and another small living room, plus access to the panoramic terrace. The house is in good condtion having been renovated a few years ago. The terrace is a fantastic spot to sit and admire the beautiful village and the spectacular views of the hills. In the village of Monteguidi you will find a friendly community. There is a bar ''circolo'', and a good trattoria ''Il Piattoforte'' close to the house. Daily bread delivery to the door as well as weekly fresh fish. There is a play area for children and a charming medieval church offering services every Sunday. There are beautiful walks in every direction all with panoramic views. Close by, there are three renowned vineyards selling wine, olive oil and honey. Throughout the year they all offer tasting events. There are horse riding facilities and stables close by.  A regular bus service links the village to Casole d''Elsa and the larger town of Colle Val d''Elsa. Casole d''Elsa is a delightful medieval town, a 10 minute drive away, with a weekly market, a good choice of grocery stores, bakeries, butchers, a pharmacy, banks, post office, bars and restaurants. There is also a small supermarket, an art school and a museum. Today Colle Val D''Elsa is famous for the production of crystal items; there''s also a museum dedicated to this activity. The Berignone National Park', 'Casole d''Elsa', 'Siena', 'toscana', 'Casole d''Elsa', 43.2974897, 11.0073049, 'https://www.idealista.it/immobile/33193777/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/de/43/83/709062668.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/de/43/83/709062668.webp"]', 28, 'semidetachedHouse', 'villa', 73.0, 98.0, 40.0, 80.0, 64.0, 61.0, 81.0, 1154.0, 'Firenze (FLR)', 59.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (17, '34994443', 230000.0, 234.0, 8, 2, 'Casale/cascina in località pergognano, 8', 'Castiglion Fiorentino - Pergognano - Stone farmhouse of approximately 234 sqm total, in a hilly and panoramic position surrounded by land owned. The building, part of a larger structure, is spread over two floors above ground. It consists on the ground floor of stables and cellars, while on the first floor, two completely independent apartments have been created with access from external stone staircases. The apartments are respectively composed of a kitchen, large living room, bathroom, and bedroom in the attic. Part of the property is a stone annex of approximately 40 sqm and land of approximately 7100 sqm, partly composed of an olive grove with about 100 productive plants, and partly arable land. The rustic house has been completely renovated, maintaining typical Tuscan finishes such as beams, terracotta tiles, and terracotta floors. Private well, municipal water, LPG heating system.', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'località pergognano, 8', 43.3390252, 11.9574533, 'https://www.idealista.it/immobile/34994443/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/8a/ff/fc/778685885.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/8a/ff/fc/778685885.webp"]', 32, 'casalicascine', 'casale', 73.0, 100.0, 40.0, 60.0, 72.0, 64.0, 78.0, 983.0, 'Firenze (FLR)', 80.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (18, '26866664', 1900000.0, 2590.0, 52, 9, 'Villa in via Poggio a Pino, 71', 'San Miniato, Tuscany – Podere Poggio al Pino: a real estate gem in the heart of the Tuscan countryside We present to you the prestigious Villa Boeri, an imposing manor villa dating back to the late 18th century, immersed in an enchanting park adorned with majestic centuries-old trees. Surrounded by over 160,000 square meters of land, the entire hill is completely independent, without any servitudes in favor of third parties, thus ensuring maximum privacy. The villa offers a breathtaking panoramic view of the gentle hills surrounding the cities of Empoli and San Miniato, with the historic tower of Federico II in plain view. On the opposite side, the hills leading to Montecatini Terme stand out, while in the distance you can admire San Gimignano and the Apuan Alps. The tower a short distance from the villa offers a spectacular view. In addition to the villa, the complex includes three other buildings for residential and tool shed use, with the possibility of developing up to twelve two-room and three-room apartments, ideal for tourist accommodation activities. The total surface area of the properties is 2,590 square meters, of which 1,260 square meters are dedicated to the manor villa, described as follows: 1. Manor Villa: an architectural masterpiece, meticulously cared for in every detail. It is spread over several floors: - Ground Floor: living area with 11 rooms and 2 bathrooms. - First Floor: sleeping area with 12 rooms and 3 bathrooms. - Attic: attic rooms. - Basement: space for use as a cellar. The various areas are connected by two elegant internal staircases. 2. Tower: a charming panoramic structure built in the early 1900s, spread over three floors with a surface area of 35 square meters. 3. Lemon House: a small 35 square meter refuge, used to protect lemons during the winter. 4. Stone Buildings: three buildings to be renovated, totaling 1,300 square meters, divided into: - Building A: with cellar, storage rooms, and two residential floors. - Building B: spa', 'San Miniato', 'Pisa', 'toscana', 'via Poggio a Pino, 71', 43.6800015, 10.8939983, 'https://www.idealista.it/immobile/26866664/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/29/3a/ed/661759759.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/29/3a/ed/661759759.webp"]', 64, 'villa', 'podere', 73.0, 100.0, 40.0, 100.0, 64.0, 65.0, 69.0, 734.0, 'Firenze (FLR)', 29.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (19, '33405754', 385000.0, 244.0, 8, 3, 'Terraced house', 'Elegant townhouse, completely restored, with garden and private infinity pool, set in the heart of a historical village on the Chianti Wine Road of Terricciola, just 30 minutes'' drive from Pisa. Walking down a tiny village street you stop in front of big wooden door which opens to let you into a charming, warm and bright house with large french windows giving views like a renaissance painting, of the beautiful Tuscan rolling hills. The house is built across three levels with a total surface of 240 sqm, comprising on the ground floor: entrance hall, large living room with french windows onto the swimming pool area, spacious kitchen opening onto the garden / pool area and with spectacular views of the valley and the hills and vineyards. Unusually, you also find a wonderful ''spa'' area with bath tub facing the beautiful views of the hills. Upstairs the master bedroom has an ensuite shower room, A/C, and a small panoramic terrace. On the mid-level are two further rooms, and two bathrooms. The living area is facing south west and can be enjoyed during every season; once the doors are opened the outdoors and indoors flow naturally together to become one big space with views, garden and pool. The house has been refurbished maintaining the original style and features: cotto tiles, exposed wooden beams, preserved architectural features like stone walls and arches. In the centre of a small village with amenities within walking distance.  Perfect location with the main seaside resorts within easy reach as are the most important artistic and cultural cities and towns of Tuscany: 5 km from Casciana Terme where the Thermal Spa Centre is open all year long; 8 km from the worldwide popular Teatro del Silenzio where every year the Bocelli international concert attracts visitors and musicians from every country in the world. Florence and Siena are located just one hour''s drive; Pisa, Lucca, San Gimignano and Volterra only 30 mins away; Pontedera with the train station and its Piaggio ', 'Terricciola', 'Pisa', 'toscana', 'Terricciola', 43.5509073, 10.649565, 'https://www.idealista.it/immobile/33405754/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/c5/e8/d7/716528208.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/c5/e8/d7/716528208.webp"]', 28, 'terracedHouse', 'villa', 73.0, 78.0, 40.0, 100.0, 64.0, 81.0, 80.0, 1578.0, 'Pisa (PSA)', 25.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (20, '33741759', 398000.0, 433.0, 12, 3, 'Detached house in via Samoggia Vecchia', 'Nel cuore della campagna bolognese, a pochi minuti da San Giovanni in Persiceto, proponiamo in vendita un affascinante casale storico del 1880, completamente da ristrutturare, situato nella tranquilla frazione di San Matteo della Decima. La proprietà è immersa in un parco privato di circa 4.000 mq, ricco di alberi ad alto fusto, ideale per chi cerca quiete, privacy e una connessione autentica con la natura. L’immobile principale si sviluppa su tre livelli per un totale di circa 460 mq e conserva elementi architettonici originali che ne raccontano il passato: al piano terra troviamo una spaziosa cucina abitabile, soggiorno, sala da pranzo, due bagni e un corridoio passante con finestre contrapposte che assicurano luce naturale e ventilazione; pavimenti in pietra, soffitti con travi a vista e un box auto completano il livello. Al primo piano si distribuiscono sette camere da letto e un bagno, ideali per una grande famiglia o per un progetto ricettivo. Il secondo piano, un ampio sottotetto, è completamente personalizzabile e si presta a diventare uno spazio abitativo o creativo aggiuntivo. Accanto al casale, un grande fienile completa la proprietà, perfetto per attività agricole, ampliamenti o spazi hobby. Una soluzione di grande fascino e potenzialità, ideale per chi cerca una residenza di campagna autentica, una seconda casa immersa nel verde o una struttura da trasformare in B&B o agriturismo.', 'San Giovanni in Persiceto', 'Bologna', 'emilia-romagna', 'via Samoggia Vecchia', 44.692905, 11.2413984, 'https://www.idealista.it/immobile/33741759/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/11/3a/07/728891048.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/11/3a/07/728891048.webp"]', 46, 'independantHouse', 'casale', 73.0, 93.0, 40.0, 100.0, 56.0, 74.0, 78.0, 919.0, 'Bologna (BLQ)', 18.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (21, '33857173', 355000.0, 474.0, 4, 4, 'Casale/cascina in strada Provinciale 7, 7', 'In a quiet and private location, we present an independent rustic house on three sides, surrounded by a private garden of approximately 2000 square meters: an oasis of peace where time seems to slow down and every detail tells a story. Renovated in 1997, this farmhouse retains all its original flavor thanks to the vaulted stone ceilings, exposed columns, and the warmth of the fireplace in the living room. The spacious and welcoming rooms are spread over two levels plus an attic, offering over 400 square meters of living space and a 219 square meter shed perfect for those who love generous spaces or want to create a hobby or workshop area. On the ground floor you will find a welcoming entrance, kitchen and dining area, bathroom-laundry room, a bedroom and a charming living room with fireplace that leads to a former renovated stable, now transformed into a unique and characterful environment. On the first floor, the sleeping area offers two double bedrooms, a balcony, an open-plan study, a walk-in closet and a bathroom. The large unfinished attic can be customized according to your needs. The exterior offers a large wooded garden, a 32 square meter canopy and all the freedom to live in contact with nature. The house is served by aqueduct water, LPG with the possibility of connecting to city gas and an artesian well. Asking price: €355,000, a charming residence, where the charm of the past meets modern life. Ref. 2257S.', 'Solarolo', 'Ravenna', 'emilia-romagna', 'strada Provinciale 7, 7', 44.3564698, 11.8714238, 'https://www.idealista.it/immobile/33857173/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ea/45/3e/732778475.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ea/45/3e/732778475.webp"]', 38, 'casalicascine', 'casale', 73.0, 100.0, 40.0, 80.0, 56.0, 70.0, 80.0, 749.0, 'Bologna (BLQ)', 50.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (22, '31020756', 370000.0, 400.0, 4, 2, 'Estate in strada Provinciale Palazzo del Pero, 14', 'Farmhouse For Sale in Palazzo del Pero Discover the timeless charm of this stone farmhouse dating back to the early 1900s, situated in a panoramic position on the hill overlooking the Valcerfone. With a surface area of approximately 400 square meters, this farmhouse offers a unique opportunity for those who desire a charming residence or a representative farmhouse. Surrounded by a large garden and 70,000 square meters of woodland, the farmhouse is composed of four buildings, with a roof completely redone in 2023 with a photovoltaic system. Inside, on the first floor, you will find a large kitchen with an original fireplace, perfect for welcoming friends and family. The four bedrooms and two additional rooms offer enough space to create personalized environments, while the possibility of converting a master bedroom on the second floor adds a touch of exclusivity. The presence of a dovecote on the roof and stables on the ground floor further enrich the authentic character of the property. With architectural elements typical of a Tuscan farmhouse, this property is ideal for those looking for a holiday home or an investment to rent out. The proximity to the city of Arezzo, reachable by car in just 10 minutes via the SS73, makes this location perfect for those who want to enjoy the tranquility of the countryside without giving up city services. Don''t miss the chance to live in a place where history and nature blend harmoniously.', 'Arezzo', 'Arezzo', 'toscana', 'strada Provinciale Palazzo del Pero, 14', 43.4182642, 11.9727994, 'https://www.idealista.it/immobile/31020756/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/56/aa/f8/640219106.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/56/aa/f8/640219106.webp"]', 58, 'countryHouse', 'palazzo', 72.0, 100.0, 40.0, 60.0, 64.0, 68.0, 79.0, 925.0, 'Firenze (FLR)', 76.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (23, '32068527', 1790000.0, 1566.0, 40, 15, 'Casale/cascina in via Piave', 'This charming village, nestled among the Tuscan hills, is located on a panoramic hill overlooking the Val di Chio, near the towns of Castiglion Fiorentino and Cortona. The village has Etruscan origins, and is composed of a main manor house, a small church, built in the 13th century and enlarged in the 18th century, with an adjoining rectory, numerous annexes, a panoramic swimming pool and surrounding land with olive groves, arable land and woodland, for approximately 5 hectares. The main building offers large spaces in the old stables on the ground floor, where brick arches create suggestive spaces and wooden beams adorn the ceiling, and where there is a large semi-professional kitchen, a tavern and a large stone room, with terracotta floors, perfect for tastings or special dinners. The bedrooms on the upper floor are large and many maintain the original terracotta floors, all with en suite bathrooms. The distribution of the spaces lends itself well to both residential use and a hospitality business (holiday home, small boutique hotel, etc. ). The building has 9 bedrooms and 10 bathrooms. The rectory villa, adjacent to the church, houses warehouses on the ground floor; on the first floor there is a living room, a kitchen, two bedrooms and three bathrooms; while on the second floor there is a bedroom and a bathroom. The windows offer enchanting views of the surrounding valley, in a landscape that guarantees peace and serenity. The properties, completely restored between the late 90s and early 2000s, are 26 km from Arezzo, 122 km from Florence and 82 km from Siena.', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'via Piave', 43.3419546, 11.9206882, 'https://www.idealista.it/immobile/32068527/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/15/0a/60/672085034.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/15/0a/60/672085034.webp"]', 29, 'casalicascine', 'casale', 72.0, 98.0, 40.0, 60.0, 72.0, 72.0, 69.0, 1143.0, 'Firenze (FLR)', 78.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (24, '33755748', 160000.0, 136.0, 4, 1, 'Village house in ristonchia, 15', 'Castiglion Fiorentino, Località Ristonchia For sale, in the small village of Ristonchia, completely renovated property with a view of the Castle of Montecchio. The rustic house, which is located in an easily accessible position, is composed as follows: On the ground floor there is a large living room with fireplace, dining room and kitchenette. On the second floor, which is accessed via a wooden staircase, there are two double bedrooms and a bathroom. The large, completely renovated tavern with double oven is accessible only from the outside. The finishes are typical Tuscan: beams and terracotta tiles, terracotta floors and stone on the interior and exterior walls. The property includes a portion of the courtyard in the front of the house.', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'ristonchia, 15', 43.3255401, 11.9695809, 'https://www.idealista.it/immobile/33755748/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/fd/68/1c/729969185.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/fd/68/1c/729969185.webp"]', 31, 'casaDePueblo', 'villa', 72.0, 97.0, 40.0, 60.0, 72.0, 61.0, 76.0, 1176.0, 'Firenze (FLR)', 82.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (25, '27894593', 940000.0, 504.0, 10, 4, 'Villa in via di Santo Stefano di Moriano, 617', 'Exclusive Listing - Villa with large park and swimming pool, located in a beautiful panoramic position on the green hills surrounding Lucca, 8 km from the historic city center and a short distance from all services. The property is on three levels and consists of: GROUND FLOOR: entrance from a large porch, open space living room overlooking a large terrace, further living room with provision for obtaining a second kitchen, study and bathroom with shower; FIRST FLOOR: hallway, one master bedroom with dressing room and en suite bathroom, three double bedrooms, one single bedroom and one bathroom with tub. All rooms have a terrace; BASEMENT FLOOR: large tavern used as living room with fireplace, dining area, kitchen, gym, one bathroom, boiler room and woodshed; The three floors are connected by internal stairs. Total area: about 500 sqm. The park, which measures approximately one hectare, is completely fenced and spread over large green areas with fruit trees, olive trees, ornamental plants, cypresses. The splendid inground swimming pool which is located in the highest part of the garden, has a size of 12 x 6 meters and is equipped with a solarium, pergola and barbecue. Also included in the sale is a portion of adjacent woodland and arable land of approximately 5000 sqm. The villa is in excellent maintenance conditions, has wooden window frames with double glazing, terracotta and parquet floors, alarm system, electric gate and oil heating for each floor. The property has also been included for many years in the tourist rental circuit with excellent revenues, making it interesting both as a private residence and as an investment. Distances: Lucca 8 km, Pisa 30 km, Florence 70 km, Versilia (sea) 30 km, Abetone (ski slopes) 60 km.', 'Lucca', 'Lucca', 'toscana', 'via di Santo Stefano di Moriano, 617', 43.9072527, 10.5244289, 'https://www.idealista.it/immobile/27894593/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ba/20/a9/528911376.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ba/20/a9/528911376.webp"]', 53, 'villa', 'villa', 72.0, 65.0, 40.0, 100.0, 85.0, 65.0, 78.0, 1865.0, 'Pisa (PSA)', 27.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (26, '33375065', 850000.0, 730.0, 17, 4, 'Villa in via del Merlo no number', 'A Timeless Tuscan Residence with Soul in the Heart of the Village In the vibrant heart of Tuscany, in Rosignano Solvay, we are honoured to present for sale a historic 18th-century residence, a gem set within a lush English garden of approximately 5,000 sqm. This unique property was commissioned by Carlo Vajani, a local son who, having sought his fortune in America, returned prosperous to fulfil a dream: to marry the woman he loved and manifest his social standing. He acquired the three blocks that today compose the palazzo, transforming them into a stately home, a symbol of a story of ambition and profound affection. The estate offers privacy and tranquillity comparable to that of the open countryside, despite being in the village centre. The main palazzo unfolds over several levels: on the ground floor, a welcoming entrance, a living room with a fireplace, a smoking room, a spacious kitchen with an office, and a service bathroom. The upper floor features three refined bedrooms and a bathroom, while the second floor offers an independent service apartment. The interiors, embellished with original antique furniture, polished ancient terracotta floors, and early 20th-century cementine tiles, are connected by a scenic Carrara white marble staircase. The generous dimensions of the bedrooms easily allow for the creation of en-suite bathrooms. The property features an old olive mill dating back to 1869, still retaining its original millstone, which has been cleverly transformed into a comfortable reception hall. Here, the majestic fireplace, the old press, and generous dining areas can accommodate up to 36 guests, all supported by a large, equipped kitchen and facilities. The residence is designated as a historic heritage property, guaranteeing tax benefits and the possibility of conservative restoration to preserve its authentic charm. An external glass elevator can also be added for easier access to the upper floors. Thanks to its significant size and proximity to renow', 'Vicopisano', 'Pisa', 'toscana', 'via del Merlo no number', 43.6825659, 10.5650882, 'https://www.idealista.it/immobile/33375065/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/38/05/14/715505182.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/38/05/14/715505182.webp"]', 99, 'villa', 'palazzo', 72.0, 97.0, 40.0, 100.0, 64.0, 65.0, 71.0, 1164.0, 'Pisa (PSA)', 14.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (27, '33621918', 990000.0, 1200.0, 28, 2, 'Villa in via Tosco Romagnola, 1097', 'Prestigious Historic Villa in the Tuscan Countryside, Cascina      In the heart of the province of Pisa, in the charming town of Cascina, stands a prestigious historic villa, nestled on a plot of approximately 4,000 square meters, a true gem exuding history and sophistication. Just minutes from Pisa Airport, less than 25 minutes from the famous Piazza dei Miracoli, and just a 40-minute drive from the renowned beaches of Forte dei Marmi, this residence exudes the elegance of bygone eras, preserving the unique architectural context intact.      Enriched by a large and secluded private park of over 3,000 square meters, it offers the perfect setting for privacy and harmony with nature, ideal for relaxing outdoors in absolute privacy. The villa, with a total surface area of approximately 1,200 square meters spread over three levels, stands out for its grandeur and harmony, offering a perfect balance of history, comfort, and generous spaces.      The ground floor, approximately 400 square meters, houses the areas dedicated to daily life and socializing. A large entrance hall leads to the spacious eat-in kitchen, ideal for family life, which leads to the living room overlooking the garden. The floor also includes several versatile rooms, easily remodeled to suit your needs, and a guest bathroom.      Ascending to the first floor, one enters the most refined and stately area of the home, intended for entertaining. Here, five bedrooms unfold, as well as two large living rooms: one of which is a majestic frescoed hall, preserving precious original pictorial decorations, an authentic expression of historical art and taste. A bathroom completes the floor.      The third and final level hosts a large attic of approximately 400 m2, consisting of seven extremely versatile rooms.      Outside, the property features a detached garage and two convenient storage rooms totaling 40 square meters, perfect for any space and practicality requirement. An additional plus is the large 240 squ', 'Cascina', 'Pisa', 'toscana', 'via Tosco Romagnola, 1097', 43.6832657, 10.5097533, 'https://www.idealista.it/immobile/33621918/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/24/36/73/724496011.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/24/36/73/724496011.webp"]', 31, 'villa', 'cascina', 72.0, 100.0, 40.0, 100.0, 64.0, 60.0, 69.0, 825.0, 'Pisa (PSA)', 9.0, NULL, 'qualified', '2026-03-12', '2026-03-12 12:44:16', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (28, '33716456', 2350000.0, 3000.0, 93, 15, 'Casale/cascina in via Solferino', '- TERRICCIOLAReal estate property consisting of a small village of buildings for residential and agricultural use of approximately 2.600 sqm plus a prestigious manor house of 440 sqm and 23 hectares of land with olive groves and arable land.The estate is located within the Pisan hills, 15 km away from Pontedera (easily reachable via the Florence - Pisa - Livorno highway), 35 km from Livorno, Castiglioncello and Volterra, 70 km from Florence in a central position both to reach the sea of Tuscany, both to reach the tourist and historical locations of the hinterland both in the Pisan, Sienese and Florentine areas.The property consists of various buildings, most of which are located in a private courtyard easily accessible via internal roads and in particular:Building consisting of 3 houses plus garage and storage room.Building consisting of 3 houses plus warehouses and agricultural warehouses on the ground floor with oven, garage, large cellar for agricultural use with storage for agricultural tools and vehicles, habitable attic and storage rooms.Building consisting of agricultural sheds with storage rooms and oven, as well as a rabbit hutch, stable and adjoining barn.Further buildings are present 200 meters away from the property and located near the town center and in particular:Small church, further home, large rooms used as cellars and warehouses for the processing and storage of wine, equipped with independent access and an external area.Important manor house dating back to 1600 of 440 sqm spread over 2 levels above ground, equipped with large independent driveway access with tree-lined avenue, courtyard, lemon house and garages, and internally composed as follows:On the ground floor, large main entrance with large frescoed living room and fireplace, large kitchen, large dining room, second living room, study and service room as well as service entrance and bathroom.On the first floor, reachable via a large and spectacular original staircase, there is a further im', 'Terricciola', 'Pisa', 'toscana', 'via Solferino', 43.5556023, 10.6416201, 'https://www.idealista.it/immobile/33716456/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e7/35/ca/727901473.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e7/35/ca/727901473.webp"]', 85, 'casalicascine', 'casale', 72.0, 100.0, 40.0, 100.0, 64.0, 62.0, 68.0, 783.0, 'Pisa (PSA)', 25.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (29, '32065949', 850000.0, 1110.0, 23, 2, 'Casale/cascina in via Roma no number', 'Tuscany, Cerreto Guidi (FI) – In the heart of the splendid Tuscan countryside, we offer for sale a prestigious estate, ideal for those who wish to immerse themselves in a context of absolute beauty and authenticity. This exclusive property extends over an area of over 100,000 square meters, characterized by large green spaces and well-kept cultivations. 75,000 square meters of land are intended for the cultivation of selected grapes and 15,000 square meters for the cultivation of olive trees, making the most of the agricultural potential of the area. The buildings within the estate cover a total area of 1,110 square meters, of which 265 square meters are used as a dwelling. The architecture perfectly reflects the Tuscan style, with elegant lines and precious materials that give a timeless charm to the property. The interiors, large and bright, have been designed to offer refined and welcoming environments, perfect for those seeking comfort, privacy and a superior quality of life. The property is sold with closed gates, including all the equipment currently present for the agricultural management and cultivation. This estate represents a unique opportunity to live immersed in the Tuscan hilly landscape, in one of the most evocative and sought-after locations in Italy. An ideal context for those seeking an exclusive property, capable of combining nature, tranquility and value.', 'Cerreto Guidi', 'Firenze', 'toscana', 'via Roma no number', 43.7584544, 10.8806906, 'https://www.idealista.it/immobile/32065949/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/99/7c/7d/672097314.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/99/7c/7d/672097314.webp"]', 62, 'casalicascine', 'casale', 72.0, 100.0, 40.0, 100.0, 64.0, 58.0, 69.0, 766.0, 'Firenze (FLR)', 27.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (30, '30680882', 540000.0, 500.0, 16, 3, 'Villa in località Taragnano, 26', 'Wonderful villa with a private chapel and panoramic views of the green Val di Chio, located in the hamlet of Taragnano, a few minutes from the town of Castiglion Fiorentino. Surrounded by 4000 meters of land, partly garden and partly olive grove; the property is accessed via a scenic tree-lined avenue that leads directly to the private parking. The villa, originally a hunting lodge, has been divided into two independent portions over the years. The portion for sale enjoys the best position and exposure with views of the Val di Chio. The property has a splendid entrance door that leads to the first floor where we find the master apartment. Through a hallway, you enter the living area, divided into a kitchen with typical Tuscan finishes, a living room with a 1500s fireplace, two communicating double bedrooms, a study, and a bathroom. A stone staircase leads to the second floor where we find a large frescoed living room with access to a large bedroom and two dressing rooms. On the ground floor, there is a third apartment completely renovated in 2023, consisting of a porch, kitchen/living room, hallway, two bedrooms, and a bathroom. It is currently rented for tourist use. Improvements have been made over the years without ever altering the style of the villa, but rather enhancing the existing materials and finishes. The property can be accessed from two driveways, one lined with cypresses, the other passing through the small village and ending in front of the Chapel dedicated to the Madonna del Conforto. The Chapel is privately owned but is always left open for passing pilgrims. The area closest to the villa is kept as a garden with some tall trees that provide shade and coolness on sunny summer days. Part of the park has been paved to allow for outdoor dinners and lunches with friends and family. At the edge of the garden, we find the land kept as an olive grove, with about 90 plants that yield a fragrant oil. The Val di Chio is an authentic natural, historical, and sc', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'località Taragnano, 26', 43.3597534, 11.9806062, 'https://www.idealista.it/immobile/30680882/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2a/7c/12/630260337.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2a/7c/12/630260337.webp"]', 70, 'villa', 'farmhouse', 71.0, 100.0, 40.0, 60.0, 72.0, 63.0, 72.0, 1080.0, 'Firenze (FLR)', 80.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (31, '34527002', 295000.0, 185.0, 7, 2, 'Villa in località Piana, 7', 'Exclusive Listing - Detached villa with large garden located in a green and open countryside setting in Valdottavo, approximately 20 minutes from the historic centre of Lucca and close to all main services. The property was completely renovated and extended in the early 1990s and is arranged over two above-ground floors with the following internal layout: GROUND FLOOR: entrance hall, spacious living and dining area with double-sided fireplace, kitchen, bathroom with shower and under-stair storage room. FIRST FLOOR: hallway, three double bedrooms and bathroom with shower. From the hallway there is access to a large, fully finished and usable attic, featuring a skylight and a distinctive round window. The two floors are connected by an internal masonry staircase with terracotta finishes. The total gross surface area of the house is approximately 170 sqm, plus about 30 sqm of attic space. The property is surrounded by a large, flat and fully fenced garden of approximately 7,000 sqm, with both pedestrian and vehicular access. An above-ground swimming pool is currently in place, with the possibility of building an in-ground pool. Additional outbuildings include a wooden storage shed of approximately 15 sqm and a small brick structure arranged over two levels of about 16 sqm, currently in a dilapidated condition but regularly registered in the land registry. The villa retains its original stone structure, with exposed chestnut wood beams and rafters, terracotta floors and stone details, while the extension was built using high-quality modern materials that blend well with the older part of the house, complemented by carefully finished interiors. Wooden windows with double glazing. Heating is autonomous and powered by LPG, with a Riello condensing boiler installed in 2021, equipped with digital thermostat and remote control, and radiators fitted with thermostatic valves. The property is connected to the public water supply and equipped with a three-chamber septic system wi', 'Borgo a Mozzano', 'Lucca', 'toscana', 'località Piana, 7', 43.9389901, 10.4788178, 'https://www.idealista.it/immobile/34527002/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/50/a3/fc/759018949.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/50/a3/fc/759018949.webp"]', 40, 'villa', 'villa', 71.0, 78.0, 40.0, 100.0, 64.0, 72.0, 76.0, 1595.0, 'Pisa (PSA)', 29.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (32, '31997453', 205000.0, 160.0, 6, 1, 'Villa in località Coletto, 45', 'A corner of peace just a stone''s throw from the village Nestled in greenery, in a residential area lived in year-round, this recently renovated villa offers tranquility and comfort. The center is within walking distance with a pleasant stroll through nature. With 14,000 sqm of land, the house is spread over a single raised level: three bedrooms, a living room, kitchen, bathroom, and a balcony overlooking the woods. On the lower floor, ample service spaces: garage, car park, technical rooms, and laundry room. An ideal retreat for those seeking beauty, privacy, and contact with nature without sacrificing proximity to services.', 'Sassello', 'Savona', 'liguria', 'località Coletto, 45', 44.4743907, 8.489922, 'https://www.idealista.it/immobile/31997453/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a8/80/60/670036271.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a8/80/60/670036271.webp"]', 33, 'villa', 'villa', 71.0, 100.0, 40.0, 100.0, 60.0, 53.0, 74.0, 1281.0, 'Genova (GOA)', 28.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (33, '34767200', 220000.0, 300.0, 4, 2, 'Detached house in località su Spantu, 1', 'Imagine waking up surrounded by silence, with sunlight filtering through the windows and the sea air just minutes from home. In the locality of Su Spantu, Capoterra metropolitan city of Cagliari, one of the most tranquil residential areas of Capoterra, we offer for sale a detached villa: an ideal solution as a second home in Sardinia, also designed for those who do not live on the island but desire a private retreat to enjoy in every season. The property, with three bedrooms, offers on the ground floor a large living area of over 40 sqm and a habitable kitchen enhanced by a fireplace. The external fixtures are recent and ensure greater living comfort. The basement adds further value and flexibility: a space to be transformed into a tavern, relaxation area, study, or guest room, adapting it to your lifestyle, with plumbing already in place. The property is completed by the roof terrace with a recently redone waterproofing membrane. Outside, the property is surrounded by a large garden of over 400 sqm on four sides, a real strong point for those who wish to fully experience the outdoor lifestyle typical of Sardinia, with privacy, greenery, and moments of outdoor conviviality. The property enjoys a strategic position, in a quiet and private residential setting, just minutes from the sea and some of the most suggestive beaches in the south of the island. Excellent connections, with Cagliari airport easily reachable. The villa requires some modernization, but offers an interesting opportunity for customization, ideal for creating a primary residence or a prestigious second home, maximizing its potential. A solution for those who dream of an independent home in Sardinia, with a garden, sun, and sea, far from the chaos but close to everything that makes the island unique.', 'Capoterra', 'Cagliari', 'sardegna', 'località su Spantu, 1', 39.1350949, 9.0083577, 'https://www.idealista.it/immobile/34767200/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2e/d3/9f/770370863.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2e/d3/9f/770370863.webp"]', 44, 'independantHouse', 'villa', 71.0, 100.0, 40.0, 100.0, 56.0, 56.0, 74.0, 733.0, 'Cagliari (CAG)', 14.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (34, '32660391', 980000.0, 1249.0, 10, 6, 'Villa in strada Nazionale per Carpi Nord, 880', 'In the heart of Motorvalley. Modena Discover this magnificent detached villa, a true historic gem located just 8 minutes from the center of Modena and the Campogalliano highway exit. Nestled in a large park, this property offers a unique atmosphere, thanks to its frescoes, stuccoes, and original decorations that tell the story of our cultural heritage. With an impressive 1,249 m² of living space, the villa is ideal for a variety of uses, such as a business center, a hotel, or a retirement home. The villa boasts an excellent layout, with 10 rooms and 6 bathrooms, making every space functional and welcoming. The property''s high visibility, combined with double driveway access, makes it ideal for those seeking a strategic investment in the heart of Emilia-Romagna. There are no restrictions limiting its use, offering the freedom to customize the interiors according to your needs. Built in the 19th century, this historic villa is an unmissable opportunity for those who appreciate the charm of Italian architecture and want to invest in a property with character and potential. With a 2,000 m² plot, the surrounding land offers green spaces perfect for events or simply to enjoy the tranquility of the Modena countryside. Don''t miss your chance to own a piece of history!', 'Modena', 'Modena', 'emilia-romagna', 'strada Nazionale per Carpi Nord, 880', 44.6797987, 10.9017718, 'https://www.idealista.it/immobile/32660391/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ed/02/d2/691169614.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ed/02/d2/691169614.webp"]', 18, 'villa', 'villa', 71.0, 100.0, 40.0, 80.0, 75.0, 54.0, 65.0, 785.0, 'Bologna (BLQ)', 35.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (35, '33752815', 475000.0, 420.0, 14, 2, 'Villa in via dell''Apparita, 30', 'Castiglion Fiorentino - we offer a large villa of approximately 410 square meters with a garden nestled in the tranquility of one of the most beautiful hills in the town. The villa, which is accessed through a private gate, is spread over three levels. On the ground floor, there is the entrance that leads to a spacious and bright living room with panoramic windows and a fireplace, a dining room, a kitchen with a tavern, a bathroom, and a multi-purpose room. On the first floor, which is accessed from the large panoramic staircase overlooking the living room, we find a large and bright study with a balcony, two single bedrooms, a master bedroom, a bathroom, a double bedroom, and a large gallery used as a living room. In the basement, there is a study and various storage rooms, as well as two garages. The living area is characterized by large windows overlooking the Val di Chiana and the garden, while for the sleeping area, a warm wooden plank floor has been chosen. Furthermore, there is air conditioning, an alarm system, and radiator heating fueled by diesel. The property is surrounded by a large terraced garden in a panoramic position, all entirely fenced. Part of the land is used as an olive grove.', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'via dell''Apparita, 30', 43.349314, 11.9151147, 'https://www.idealista.it/immobile/33752815/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2c/1f/2c/729257961.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2c/1f/2c/729257961.webp"]', 52, 'villa', 'villa', 70.0, 99.0, 40.0, 60.0, 72.0, 57.0, 71.0, 1131.0, 'Firenze (FLR)', 77.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (36, '27711812', 695000.0, 550.0, 17, 6, 'Villa in via di Tofori, 70', 'Large villa located on the hills of Lucca in Tofori, in a beautiful panoramic position and with excellent sun exposure. The villa is divided into three real estate units, each with an independent entrance and consists of: APARTMENT 1: Ground Floor: entrance, large living room, kitchen with fireplace, dressing room, bathroom with shower and closet / laundry. It also has a large loggia with access to the garden. 1st Floor: hallway, double bedroom, single bedroom, study and bathroom with shower; 2nd Floor: hallway, double bedroom, twin bedroom and bathroom with tub; APARTMENT 2: Ground Floor: entrance, living room, kitchen, pantry and a large cellar room connected both inside and outside with an independent entrance; 1st Floor: hallway, 2 double bedrooms, single bedroom and bathroom with shower. APARTMENT 3: Ground Floor: porch, cellar and laundry with independent entrances; 1st Floor: entrance, kitchen-living room with fireplace, bathroom, double bedroom, closet and bathroom with shower. The property is also equipped with 2 other large rooms adjacent to apartment 3, which can be used as a garage, laundry and thermal room on the ground floor and a large room on the first floor that can be connected to apartment 3 to create another bathroom or large living room. Total area: 550 sqm. The property has 1.2 hectares of land, completely fenced, partly cultivated with olive groves and partly for garden use with various ornamental plants, with the possibility of making another driveway and building a swimming pool. The property was built in 1900, and is in good structural and maintenance conditions. Apartment 1 was completely renovated in 1995, apartment 3 was renovated in 2017, while apartment 2 needs some renovations (electrical and heating system and new bathroom). LPG heating system. Distances: 10 km from Lucca, 30 km from Pisa, 50 km from Florence, 35 km from Versilia (sea), 70 km from Abetone (ski slopes).', 'Capannori', 'Lucca', 'toscana', 'via di Tofori, 70', 43.8823964, 10.6093076, 'https://www.idealista.it/immobile/27711812/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/70/82/81/521114082.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/70/82/81/521114082.webp"]', 47, 'villa', 'villa', 70.0, 93.0, 40.0, 100.0, 64.0, 62.0, 68.0, 1264.0, 'Pisa (PSA)', 28.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (37, '35029141', 480000.0, 300.0, 8, 3, 'Casale/cascina in località Podere Scopeto, 19', 'Nestled in the heart of the beautiful Tuscan countryside, among the enchanting hills connecting Volterra and Colle Val d''Elsa, we are pleased to present this extraordinary farmhouse, a true corner of paradise, open on four sides, complete with a garden and swimming pool. This charming property extends over two floors. On the ground floor, you''ll find a spacious living room with a fireplace, inviting moments of conviviality and relaxation, illuminated by large windows offering direct access to the garden. The eat-in kitchen is the heart of the home, ideal for preparing delicious dinners with family or friends, while the dining room, with its large windows, offers breathtaking views of the surrounding countryside, making every meal a unique experience. Completing this level is a practical laundry room and a spacious bathroom with a shower and window. An internal staircase leads to the first floor, where the sleeping area is located, comprising four spacious double bedrooms, perfect for maximum comfort and privacy. One of the bedrooms boasts a walk-in closet and a private bathroom, while a second bathroom serves the other bedrooms, ensuring practicality and functionality. Surrounded by a large, well-maintained garden, the property offers several outdoor areas for leisure and relaxation. Imagine hosting unforgettable barbecues in the barbecue area or relaxing under the gazebo, perhaps sipping a fine local wine. And that''s not all: the swimming pool and solarium are the ideal place to cool off on hot summer days, immersed in the tranquility of nature. The house is easily accessible via approximately 5 km of well-maintained dirt road, allowing you to enjoy the peace and serenity of the countryside while remaining just 20 km from the center of Volterra and 23 km from Colle Val d''Elsa. Don''t miss this unique opportunity to live in a dream corner of Tuscany, where every day can become a new adventure, rediscovering the charm of times gone by, yet with all the modern comforts', 'Volterra', 'Pisa', 'toscana', 'località Podere Scopeto, 19', 43.3575455, 10.9810671, 'https://www.idealista.it/immobile/35029141/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/55/15/03/778152087.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/55/15/03/778152087.webp"]', 50, 'casalicascine', 'casale', 70.0, 77.0, 40.0, 80.0, 64.0, 72.0, 79.0, 1600.0, 'Firenze (FLR)', 53.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (38, '32177037', 185000.0, 133.0, 7, 2, 'Villa in via Giaccheri, 19', 'For sale: splendid country house! Located in a quiet position, this wonderful single-story home offers all the space you need. The property includes: a spacious and functional kitchen, a large living room for relaxation and socializing, three bright bedrooms, two modern bathrooms, a charming wooden porch, perfect for enjoying the outdoors, a shed ideal for parking cars or for other uses. Furthermore, the large surrounding garden of 6000 sqm, partly paved with interlocking bricks, represents a rare opportunity. It is extremely versatile and can be easily adapted to create a vegetable garden or to install a swimming pool. Don''t miss this unique opportunity! Contact us for more information and to book a visit.', 'Mioglia', 'Savona', 'liguria', 'via Giaccheri, 19', 44.4803439, 8.4042675, 'https://www.idealista.it/immobile/32177037/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/75/8a/5c/675979920.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/75/8a/5c/675979920.webp"]', 26, 'villa', 'villa', 70.0, 100.0, 40.0, 80.0, 60.0, 58.0, 74.0, 1391.0, 'Genova (GOA)', 35.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (39, '33387491', 370000.0, 640.0, 30, 7, 'Castle', 'AM-7542 MONTEFIORINO – GUSCIOLA We offer a magnificent stone farmhouse of large dimensions, with a garden/park of approximately 7,500 sqm. Known as the Castle of Gusciola, it stands on a panoramic hill in the Modena Apennines, in the heart of the municipality of Montefiorino. Its origins date back to the Middle Ages, when it was a lookout and territorial stronghold. Situated along ancient communication routes between Emilia and Tuscany, the castle witnessed armed passages, religious events, and folk stories. Its original stone structure has been carefully preserved and enhanced over the years, maintaining the charm of the fortified dwellings typical of the Apennines. It was recently used by the current owners as a guesthouse for themed dinners and private events. It is perfectly suited as a hospitality business (B&B, hotel, restaurant), but also ideal for those seeking a prestigious and unique residence, far from traffic and heat, yet still close to the plains and industrial areas—just 45 minutes from Sassuolo and about 1 hour from Modena and Reggio Emilia. Highlights: Unique location: a blend of medieval history, mystery, and pop culture. Strong brand identity: presence in media and social networks. Flexible use: ideal for weddings, corporate events, film sets, educational activities. Expansion potential: possibility to add services such as a historic spa, glamping, or interactive educational experiences.', 'Montefiorino', 'Modena', 'emilia-romagna', 'Montefiorino', 44.3513977, 10.5871868, 'https://www.idealista.it/immobile/33387491/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7f/16/ae/715908019.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7f/16/ae/715908019.webp"]', 32, 'castillo', 'farmhouse', 70.0, 100.0, 40.0, 80.0, 56.0, 58.0, 74.0, 578.0, 'Bologna (BLQ)', 59.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (40, '33930662', 310000.0, 500.0, 6, 3, 'Villa in via Vittorio Emanuele II, 42', 'MGRV0077 - FOR INFORMATION AND VIEWINGS CONTACT OUR REAL ESTATE CONSULTANT MARCO AT [PHONE NUMBER] ALSO VIA SMS-WHATSAPP *** OVIGLIO AL - VIA VITTORIO EMANUELE II 44 *** We offer in a quiet and sunny location a splendid Villa surrounded by its green and planted garden. The property, architecturally designed in a modern and unique style, has a total area of 500sqm divided over three levels, while the land on which it stands, 5,200sqm, consists of a garden, lawn, and vegetable patch. Access is from the entrance into the large and high double living room with a marble-clad fireplace on an exposed brick wall and a convivial dining area from which to access the terrace with awnings, a eat-in kitchen, a hallway leading to the sleeping area with three spacious bedrooms, a bathroom with a bathtub, and a service bathroom with a shower. Near the entrance is the convenient laundry room. Centrally, the open staircase with iron railings leads to the first floor where, on a mezzanine, we find the second living room, to the side the fourth attic room to be used as a study or fourth bedroom with an adjoining third bathroom ready to be furnished, a large rear terrace above the ground floor terrace, and a small front terrace. Going down into the basement, we find a garage suitable for four cars, a cellar, and three large rooms for storage, which could be used as a tavern or a second laundry room if desired. The heating and cooling of the rooms is done with a programmable underfloor radiant system for each floor. The villa has Cotto d''Este flooring on the ground floor, while parquet covers the entire first floor from the stairs upwards. External walls in hand-formed bricks, car path and courtyard in interlocking paving stones, ramp for descent into the basement is heated to prevent ice in winter, thus making access safe even in the cold season. The entire basement is protected by a cavity wall that prevents rising damp in the house. Automatic gate on the road and automatic basement do', 'Oviglio', 'Alessandria', 'piemonte', 'via Vittorio Emanuele II, 42', 44.8643286, 8.4864925, 'https://www.idealista.it/immobile/33930662/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/65/e8/84/773895559.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/65/e8/84/773895559.webp"]', 94, 'villa', 'villa', 70.0, 94.0, 15.0, 80.0, 54.0, 77.0, 81.0, 620.0, 'Genova (GOA)', 57.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (41, '33136726', 1350000.0, 1100.0, 36, 8, 'Villa in Sp46, 18', 'Charming old villa in a small hamlet set in the hills near Pisa, an oasis of peace and tranquility. Description The property from the important square footage of over 1,000 square meters in total and whose origins date back to 1700 is composed of two specular units each arranged on two levels, on the ground floor both have the living area characterized by large rooms with fireplaces, noteworthy the fireplace in the kitchen and the two fireplaces in the main rooms in the main unit, while on the second floor the sleeping area with bedrooms, bathrooms some private and living rooms that disengage these rooms. Next to the main unit is a small apartment ideal as a guest house, studio or guest quarters. At the back, with separate entrance, another apartment, with generous square footage, connected to both the large cellars and the attic with significant heights. Outdoor spaces A large garage connected to the cellars and the what allows you to comfortably park two cars in a row, the garden is divided into three distinct areas, so that each apartment has its own outdoor space, ensuring total privacy and relaxing moments to share with friends. At the back, a large plot of land of about 2,500 square meters hosts a variety of fruit trees, creating a rural and natural atmosphere, perfect for those who love contact with nature or want to cultivate a vegetable garden, or create a swimming pool overlooking the surrounding countryside. Condition and finishes The villa was renovated in the late 1990s with recovery and use of typical materials, to preserve the typical Tuscan style. Over the years numerous works have been done to keep the villa at a consistently high quality standard and in step with the times. The roof has been insulated and photovoltaic panels have been installed for a better energy efficiency of the property. The apartment at the back, with the cellars and the attic need a major renovation to make the most of it. Potential uses This villa represents a unique opportu', 'Casciana Terme Lari', 'Pisa', 'toscana', 'SP46, 18', 43.5617741, 10.5976133, 'https://www.idealista.it/immobile/33136726/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/cb/e4/d4/706989330.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/cb/e4/d4/706989330.webp"]', 48, 'villa', 'villa', 69.0, 94.0, 40.0, 100.0, 64.0, 62.0, 63.0, 1227.0, 'Pisa (PSA)', 21.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (42, '29049613', 125000.0, 340.0, 18, 4, 'Villa in località Buschiazzi no number', 'In the heart of the Beigua nature reserve, we offer this manor house with over 4000sqm of fenced parkland. The house consists of two mirror-image apartments with independent entrances, each with a living area on the ground floor, a living room with a fireplace, a bathroom, and four bedrooms and another bathroom on the upper floor. In the front part, there is a large common room for both apartments, equipped with a fireplace and overlooking the park. The villa, built in the 70s, has a reinforced concrete structure and interesting architectural features.. . with Art Nouveau influences and exposed stone details typical of the area. The center of Piampaludo with its old grocery store, bar, and an excellent trattoria.. . all within walking distance. The summit of Mount Beigua is a 15-minute drive away, and the Ligurian coast is an hour away.', 'Sassello', 'Savona', 'liguria', 'località Buschiazzi no number', 44.4610034, 8.5810936, 'https://www.idealista.it/immobile/29049613/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/04/bf/16/611707139.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/04/bf/16/611707139.webp"]', 48, 'villa', 'villa', 69.0, 100.0, 40.0, 100.0, 60.0, 60.0, 61.0, 368.0, 'Genova (GOA)', 21.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (43, '34331563', 549000.0, 350.0, 8, 2, 'Villa in via Rive, 31', 'Boissano, Just 5 minutes from the heart of Loano, in a sunny position, we offer for sale this large, customizable and completely independent villa with a splendid sea and panoramic view. The property is ideal both as a single residence and as a two-family solution thanks to the presence of internal and external connections between the various levels, each enhanced by private gardens and terraces with views. On the ground floor, after crossing a large courtyard with driveway access perfect for parking at least four cars, you are welcomed by a large living room, a eat-in kitchen, a double bedroom and a bathroom, as well as a garden perfect for pleasant moments of relaxation. The first floor houses a bright hallway, a living room with an open-plan kitchen, two bedrooms, a bathroom and access to a panoramic terrace and its portion of the garden, perfect for outdoor dining and moments of peace immersed in greenery. Going up to the second floor, a large hallway leads to a bedroom, a bathroom and a wonderful loggia terrace, livable and full of charm, from which to enjoy a breathtaking sea view and the harmony of the surrounding landscape, with direct access to the floor''s garden. The property is completed by a spacious cellar/storage room of approximately 25 sqm and a large garage of approximately 150 sqm capable of comfortably accommodating 4/5 cars. A residence with a unique character, designed for those who wish to experience the beauty of the Riviera in an exclusive and comfortable setting. Some images in this advertisement represent a graphic elaboration via AI for illustrative purposes of a potential internal and external renovation of the property. You can contact us without obligation to obtain more information and/or to book a visit to this independent villa in Boissano.', 'Boissano', 'Savona', 'liguria', 'via Rive, 31', 44.1334506, 8.2336565, 'https://www.idealista.it/immobile/34331563/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/52/25/28/750210870.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/52/25/28/750210870.webp"]', 40, 'villa', 'villa', 69.0, 94.0, 40.0, 80.0, 60.0, 57.0, 72.0, 1569.0, 'Genova (GOA)', 57.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (44, '33963208', 1700000.0, 1400.0, 34, 15, 'Villa in strada Provinciale del Cornocchio, 55', 'For Sale: Stunning Detached Villa in San Gimignano! Immersed in the enchanting Tuscan landscape, we offer for sale an extraordinary detached villa located in the municipality of San Gimignano, on the border with the municipality of Volterra. This marvelous property, free on four sides, extends over two levels and boasts a large swimming pool and an exclusive park surrounding it, making it the ideal choice for those seeking tranquility and beauty. The villa, with its characteristic horseshoe shape surrounding a welcoming central courtyard, is already divided into five independent apartments, an office, and several storage rooms and cellars, as well as a garage for agricultural machinery on the ground floor. Each apartment has its own private entrance, ensuring privacy and independence. On the ground floor, there are two four-room apartments, each comprising a kitchen, living room, two bedrooms, and a bathroom. A third apartment, located on the first floor, offers three rooms with a bright kitchen/living room, two bedrooms, and a bathroom, perfect for families or groups of friends. But there''s more! Also on the first floor are two very spacious apartments, each with a kitchen and a large living room that opens onto a covered loggia overlooking the farmyard. These apartments feature six bedrooms, each with a private bathroom, ideal for guests or as accommodations. The park surrounding the villa is more than just a green space, but a true corner of paradise where you can enjoy relaxing poolside or hosting unforgettable al fresco dinners. This villa represents a unique opportunity for those looking to invest in a prestigious property in one of the most beautiful areas of Tuscany. Don''t miss the chance to live in this enchanting setting! Contact us for more information and to schedule a viewing. Your new life awaits you in San Gimignano!', 'San Gimignano', 'Siena', 'toscana', 'strada Provinciale del Cornocchio, 55', 43.4140156, 10.9795538, 'https://www.idealista.it/immobile/33963208/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/4e/37/f2/736401202.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/4e/37/f2/736401202.webp"]', 54, 'villa', 'villa', 68.0, 95.0, 40.0, 80.0, 64.0, 61.0, 65.0, 1214.0, 'Firenze (FLR)', 48.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (45, '31853107', 219000.0, 175.0, 7, 1, 'Villa in Montecchio, 334 ---/a', 'Independent House for Sale in Montecchio, Castiglion Fiorentino Discover the charm of living at the foot of the historic Montecchio Castle with this splendid independent house located in a quiet residential area. This property offers ample space for the whole family. On the first floor, you will find a welcoming entrance hall, a corridor leading to a habitable kitchen, a bright living room, two double bedrooms, a bathroom and a practical storage room. The ground floor is equally versatile, with a second kitchen, a bathroom, a multi-purpose room, a garage and a cellar. The exterior of the house is a true green paradise: a large garden with about 20 olive trees that guarantee an oil production sufficient for the family''s needs. The balcony offers ideal spaces to enjoy the panoramic view and the mild Tuscan climate. Built in 1967 and maintained in good condition, the house is equipped with radiator heating and enjoys excellent exposure on all sides. With a plot of about 400 m², and double driveway access, this property represents a unique opportunity for those seeking a spacious house surrounded by nature, without sacrificing the convenience of proximity to services. Don''t miss the opportunity to live in one of the most fascinating locations in Tuscany!', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'Montecchio, 334 ---/A', 43.3147794, 11.9253218, 'https://www.idealista.it/immobile/31853107/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ed/1b/70/668909641.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ed/1b/70/668909641.webp"]', 33, 'villa', 'villa', 68.0, 93.0, 40.0, 60.0, 72.0, 51.0, 73.0, 1251.0, 'Firenze (FLR)', 80.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (46, '33971300', 380000.0, 295.0, 11, 4, 'Villa in piazza Indipendenza', 'DINNERS UNDER THE PERGOLA, OUTDOOR JACUZZI, AND MOUNT AMIATA 20 MINUTES AWAY  THE TUSCANY YOU REALLY EXPERIENCE  There''s a simple way to tell if a house in Tuscany is the right one: sit under the pergola, smell the scent of the wood, the glass on the table, the fire just waiting for a spark. If you see yourself there, it''s done. Here, the scene is set: exposed beams, stone, real fireplaces, and outside, a greenery inviting friends, children, and guests. You''re not buying an address, but a life that flows.  TUSCAN TRADITION, MODERN COMFORT  The villa is free on four sides, in the countryside of Arcidosso. Inside, it boasts some impressive square footage: approximately three hundred square meters spread across two levels, with an additional bedroom built into the attic. It was completely renovated from foundation to roof in 2012, and it shows. Upon entering, you''ll find the right choices: beams and bricks, terracotta floors, exposed stone, and double-glazed windows. The living area is spacious, with the lounge opening into two rooms, and the kitchen opens to the outside. There are four bedrooms, four bathrooms, and each room has a fireplace or wood-burning stove. Central heating is provided. It''s a ready-to-move-in home: you arrive with your suitcase, not with a construction company.  LOVE PRIVACY BUT DON''T WANT ISOLATION?  Those who buy here often fear two things: being too far away from everyone or too close to everyone. This villa solves both. You''re just far enough from other homes to feel free, yet the paved road takes you right to the gate. Arcidosso''s amenities are within easy reach for quick errands, without any impossible roads. And when you''re hosting a large dinner party, parking isn''t a problem: there''s room for cars, and maneuvering is easy.  OUTDOOR SPACE MUST BE USEFUL, NOT A FACADE  How often does "large garden" mean a strip of grass you don''t know how to use. Here, space makes sense: almost five thousand meters of woodland and arable land. The paved c', 'Arcidosso', 'Grosseto', 'toscana', 'piazza Indipendenza', 42.8700874, 11.5397625, 'https://www.idealista.it/immobile/33971300/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/df/79/3c/736682517.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/df/79/3c/736682517.webp"]', 48, 'villa', 'villa', 68.0, 91.0, 40.0, 40.0, 64.0, 64.0, 78.0, 1288.0, 'Firenze (FLR)', 108.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (47, '30087545', 2920000.0, 1800.0, 40, 9, 'Villa in via di Campo Lungo, 16', 'VILLA TRUDY - Exclusive Historic Estate for Sale in the Tuscan Countryside with Vineyard, Olive Grove, Woodland, and Pool, Just a Few Kilometers from Lucca''s Historic Center The prestigious estate for sale, located in the Lucca countryside, is a short distance from a charming medieval village. The property dates back to the 16th century and includes approximately 1,800 square meters of buildings, divided into the main villa, a guesthouse, an ancient barn, a chapel, a lemon house, and additional storage buildings. The estate spans about 5.8 hectares of land and outdoor spaces, featuring a small vineyard, woodland, an olive grove, a pool, and a secret courtyard. The main villa, spread over four levels basement, mezzanine, first floor, and attic covers a total area of about 1,180 square meters and requires renovation to restore its former glory. Currently, it consists of large halls, service rooms, nine bedrooms, and four bathrooms. The structure is an enchanting blend of 17th-century architecture and later expansions. The basement houses the historic cellars, which tell ancient traditions. Originally used to store wine and oil, these spacious areas can now host events and gatherings. On the raised mezzanine floor, the main entrance opens into a large frescoed hall, situated at the center of the villa. From here, you can access the kitchen with a dining room, a living room with a tea room, the library, and two bedrooms with a shared bathroom.  Ascending to the first floor via a scenic staircase with a gallery, you are led to a spacious living room and a reading room, which separate seven bedrooms served by two shared bathrooms. An additional service staircase leads to the expansive attic, consisting of various partially habitable spaces that can be transformed into multi-purpose rooms or additional bedrooms. In front of the historic villa is the guesthouse, a classic Tuscan farmhouse completely renovated with extreme elegance. It spans 330 square meters and includes si', 'Capannori', 'Lucca', 'toscana', 'via di Campo Lungo, 16', 43.7685676, 10.5966766, 'https://www.idealista.it/immobile/30087545/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/23/1a/93/612251691.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/23/1a/93/612251691.webp"]', 63, 'villa', 'farmhouse', 68.0, 76.0, 40.0, 100.0, 64.0, 73.0, 66.0, 1622.0, 'Pisa (PSA)', 19.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (48, '32505777', 720000.0, 670.0, 12, 5, 'Estate in Azienda Agricola Bruchi Gabriele', 'Where the land tells ancient stories and silence knows how to speak to the heart. Just a stone''s throw from Pomarance, hidden among the soft hills of Tuscany, there is a place that you don''t just visit - you live, breathe and love. A 30-hectare farm where nature is still master, and every detail has the flavor of truth: 2,300 olive trees draw the landscape like a caress, a vineyard welcomes the dreams of autumn, and ten centuries-old oaks guard time with the wisdom of silent giants. The main farmhouse - 600 sqm of stone, light and memory - opens discreetly, offering 8 rooms, 5 bathrooms and spaces that tell of summer dinners, winter fires, slow awakenings. The outhouse with fireplace and wood stove is a small refuge of warmth and authenticity. The barn and cellar with steel barrels are the beating heart of a life in harmony with the land. Here, every season has its own voice. Every sunrise a promise. And distance does not weigh: Volterra is half an hour away, Siena and the sea only an hour away - close enough to be reached, far enough to remain a dream. This is not just a farm. It is a return. A beginning. A choice of love.', 'Pomarance', 'Pisa', 'toscana', 'Azienda Agricola Bruchi Gabriele', 43.2824868, 10.8921937, 'https://www.idealista.it/immobile/32505777/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/8b/19/8d/686198361.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/8b/19/8d/686198361.webp"]', 45, 'countryHouse', 'farmhouse', 68.0, 100.0, 40.0, 60.0, 64.0, 62.0, 67.0, 1075.0, 'Pisa (PSA)', 60.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (49, '34130682', 171000.0, 271.0, 5, 2, 'Semi-detached house in corso Repubblica no number', 'In auction semi-detached villa, arranged on two levels, composed on the ground floor of: entrance, living room, dining room, kitchen, closet, bathroom and staircase to access the upper floor, where we find: hallway, two bathrooms, two balconies, large terrace and four bedrooms. The solution is completed by the courtyard, shed used as a tool shed and a second small building consisting of: rustic kitchen, bathroom and closet. We receive by appointment in our offices in Olbia, Milan and Pavia 100% MORTGAGE POSSIBILITY. Buying a property at auction allows an average saving on market prices of over 30%, with savings that can even exceed 50%. In virtue of these considerations, our company has decided to offer our customers the opportunity to seize all investment opportunities in real estate auctions from all Italian courts, through collaboration with a consulting company operating throughout the national territory, specialized in real estate auctions to assist you at our offices at 360°, from the selection of the property, up to the delivery of the keys by the Court and also in the subsequent phases for any further needs. We are therefore at your disposal for an in-depth meeting regarding this real estate opportunity at auction without excluding any other opportunities for pre-auction purchases in the so-called "balance and write-offs". 360° ASSISTANCE, JOINT VISIT, 100% SAFE PURCHASE, POSSIBILITY OF MORTGAGE UP TO 100%, COMPARED TO MARKET PRICES, AVERAGE SAVING OF 50% SAVING ALSO ON ACCESSORY COSTS. Once a property has been awarded/purchased at auction or pre-auction, our 360° assistance continues even if you want to resell it, put it to income or if you want to sell another real estate unit such as your first home.', 'Orune', 'Nuoro', 'sardegna', 'corso Repubblica no number', 40.4093618, 9.3698223, 'https://www.idealista.it/immobile/34130682/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7f/87/86/742631540.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7f/87/86/742631540.webp"]', 31, 'semidetachedHouse', 'villa', 68.0, 100.0, 40.0, 80.0, 56.0, 50.0, 74.0, 631.0, 'Olbia (OLB)', 56.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (50, '32651141', 180000.0, 198.0, 7, 1, 'Villa in località Leprato, 14', 'Detached house surrounded by the greenery of Alta Langa In one of the most evocative areas of Alta Langa, immersed in the peace and greenery of the countryside, a detached house on four sides, ideal for those who wish to live or spend their free time in a relaxing and authentic setting. The property is spread over several levels, offering ample and well-distributed spaces. On the ground floor, a very spacious garage welcomes us, ideal for multiple cars or for those who need a workspace. We then find a cellar, a storage room, and several closets, very useful for keeping everything tidy and at hand, without sacrificing practicality. Going up to the first floor, the living area opens up: a functional kitchenette, a bright living room with a wood-burning fireplace, three bedrooms, and a bathroom recently renovated along with the plumbing and electrical systems. From the master bedroom, there is direct access to a terrace with an open view of the countryside. The house also has a large attic space, easily convertible into a study, a hobby room, or a fourth bedroom. The property is completed by a large private garden of 3,800 sqm, perfect for installing a swimming pool or a relaxation area. A unique opportunity for those seeking a quiet yet convenient home, just a few minutes from essential services, in the authentic heart of the Langhe. The Dotta real estate agency has stood out in the local market for years thanks to the extreme seriousness and competence of its staff. It is part of our mission to accompany the client in the process of evaluating and choosing the property that best suits their expectations and needs. Contact us immediately to view this house in the Langhe together. We will be happy to accompany you to the property without any obligation, with courtesy and professionalism.', 'Serravalle Langhe', 'Cuneo', 'piemonte', 'località Leprato, 14', 44.5549173, 8.0691657, 'https://www.idealista.it/immobile/32651141/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/26/bc/1f/690894455.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/26/bc/1f/690894455.webp"]', 20, 'villa', 'villa', 68.0, 67.0, 15.0, 60.0, 92.0, 60.0, 82.0, 909.0, 'Genova (GOA)', 63.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (51, '23622155', 1550000.0, 900.0, 25, 12, 'Casale/cascina in via Roma no number', 'VILLA DEL BORGO: IMPORTANT MANOR HOUSE IN A 16TH CENTURY VILLAGE IN THE COUNTRYSIDE OF MONTALCINO, SIENA, TUSCANY Important 17th century manor house on the edge of a small agricultural village in a panoramic area immersed in the Sienese countryside. Impeccably restored with a final result of a high quality and formal level.On three levels, each floor houses an important residence of about 300 square meters, connected by the magnificent original travertine staircase, with a modern lift hidden by ancient doors. High plant engineering and finishing standing, large arched doors overlooking the park, original fireplaces and frescoes, ancient and generous beams.Each floor has maintained its own personal and exclusive style, making this property a particularly charming Residence. The private park of the Villa extends for about 1 ha, includes a beautiful Italian Garden with age-old trees of about 5000 square meters with automatic irrigation system, beautiful green lawns and an enchanting swimming pool. The owners recently discovered an active thermal spring, which could be transformed into an incredible private spa. Of great style and elegance, Villa del Borgo is perfect as a prestigious residence, or dedicated to luxury tourism. SITUATION Manor house in the heart of a small medieval village in the Montalcino countryside.A few minutes from the hamlet of Torrenieri (supermarket, grocery, pharmacy, newspapers, pastry shop, restaurants, pizzeria), and 6km from Montalcino. Famous for its Brunello wine and for its Fortress, it has splendid views over the Sienese countryside, and offers every comfort: numerous restaurants, banks, post office, pharmacy, schools, weekly market, supermarket, groceries, interesting museums and cinema-theater. This property is located 20 minutes from ''The Club'' in Castiglion del Bosco, the only private Golf Club in Italy and 40 minutes from Siena. THE HOUSE Villa del Borgo is spread over three floors, each of 300 square meters, connected by a beautifu', 'Montalcino', 'Siena', 'toscana', 'via Roma no number', 43.0606921, 11.4883349, 'https://www.idealista.it/immobile/23622155/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/3e/34/db/374192675.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/3e/34/db/374192675.webp"]', 44, 'casalicascine', 'casale', 67.0, 72.0, 40.0, 60.0, 64.0, 85.0, 69.0, 1722.0, 'Firenze (FLR)', 86.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (52, '33165699', 48000.0, 92.0, 3, 1, 'Village house in Ristonchia, 2', 'Country house for Sale in Ristonchia Discover the authentic charm of Tuscany with this enchanting country house located in the picturesque village of Ristonchia. This property, in need of renovation, is spread over two floors, offering a unique opportunity to create your ideal residence. Access is via a charming external staircase with a small terrace that leads to a typical country kitchen, equipped with a large fireplace, perfect for heating the rooms and cooking delicious dishes. On the first floor, you will find a spacious bedroom with a bathroom and a cozy additional room, ideal for guests or as a study. The property maintains classic Tuscan features, such as the original terracotta flooring and exposed beams that create a warm and welcoming atmosphere. In addition, the two large cellars on the ground floor offer extraordinary potential, with the possibility of connecting them to the main house. With a commercial area of 92 m² and an orientation that guarantees brightness, this house represents an unmissable opportunity for those who wish to immerse themselves in Tuscan rural life. Don''t miss this opportunity to renovate a piece of history and transform it into your dream home!', 'Castiglion Fiorentino', 'Arezzo', 'toscana', 'Ristonchia, 2', 43.3258208, 11.9696586, 'https://www.idealista.it/immobile/33165699/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ae/7e/b2/711680971.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ae/7e/b2/711680971.webp"]', 28, 'casaDePueblo', 'villa', 67.0, 100.0, 40.0, 60.0, 72.0, 58.0, 59.0, 522.0, 'Firenze (FLR)', 82.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (53, '34117436', 570000.0, 326.0, 11, 3, 'Casale/cascina in campagna circostante', '€ 570,000 A balance of nature, comfort, and Tuscan authenticity. In a dominant and perfectly accessible position, this farmhouse of over 250 sqm is set in a landscape of rare harmony. A secluded hilltop, surrounded by cypress trees and rolling hills, where tranquility is authentic but never isolated: the sea is ten minutes away, and the amenities of the town center are five minutes away. The house, spread over multiple levels, retains the solidity and charm of Tuscan rural architecture, offering ample volumes to be reinterpreted with contemporary taste. The required interventions are more aesthetic than structural: a perfect canvas for those who desire a respectful yet personalized restoration. On the ground floor, a bright living room with a fireplace opens up, a convivial space that communicates with the eat-in kitchen and the dining room, as well as a double bedroom flanked by two bathrooms. On the upper floor, two generously sized double bedrooms overlook the private park, sharing a panoramic terrace that captures the sunset light and the soul of the Maremma. The property is completed by three storage rooms and an ancient stone tank, now a scenic element that can easily become a swimming pool. The entire area – approximately 8,000 sqm, of which 5,000 are fenced – is orderly and well-maintained, with driveway access and a private gate. All utilities are active: municipal aqueduct, electricity, LPG heating, and an artesian well. Facing southwest, the house receives full daylight and the most intense sunsets that the Maremma has to offer. A farmhouse that combines authenticity, beauty, and ease of living: the Tuscan countryside, finally, without compromise.', 'Scarlino', 'Grosseto', 'toscana', 'campagna circostante', 42.9554621, 10.8274055, 'https://www.idealista.it/immobile/34117436/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/52/73/38/742179475.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/52/73/38/742179475.webp"]', 35, 'casalicascine', 'casale', 67.0, 71.0, 40.0, 60.0, 64.0, 80.0, 73.0, 1748.0, 'Pisa (PSA)', 88.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (54, '27148496', 790000.0, 500.0, 20, 5, 'Villa in via Cappelletta, 3', 'Pietra Ligure, in the beautiful and characteristic Ligurian hinterland, about 4 km from the beaches, with a view of the sea in contrast with the green of the olive groves where perfumes and aromas mix with the tranquility of the countryside, we offer a prestigious independent villa with land. The property of about 500 square meters currently consists of three real estate units, two of which on the first floor and one on the second floor as well as an attic. Large terraces with sea and panoramic views, land of over 3000 square meters planted, cultivated and well cared for. Large garage, particular equipped cellar, various outdoor parking spaces and differentiated entrances in order to make access to all the real estate units independent. The property lends itself perfectly to future use as an accommodation facility or B&B. The systems serving it are compliant and have the relevant certifications. Unique opportunity in terms of location and size, suitable for lovers of tranquility and/or investors for an excellent and guaranteed income. You can contact us without obligation, to get more information and/or book a visit to this prestigious villa in the hinterland of Pietra Ligure.', 'Pietra Ligure', 'Savona', 'liguria', 'via Cappelletta, 3', 44.1549967, 8.2625334, 'https://www.idealista.it/immobile/27148496/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/21/10/f8/499779536.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/21/10/f8/499779536.webp"]', 52, 'villa', 'villa', 67.0, 94.0, 40.0, 80.0, 60.0, 56.0, 66.0, 1580.0, 'Genova (GOA)', 54.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (55, '30199963', 920000.0, 600.0, 10, 6, 'Villa in Variante Aurelia no number', 'Villa Marinasco In an excellent strategic position overlooking the sea of the Gulf of La Spezia, but a short distance from the Cinque Terre National Park and the Gulf of Poets, surrounded by a splendid 1700 sqm garden with large terraces offering an enchanting view of the sea, Villa Marinasco is a prestigious and elegant historic villa from the early 1900s in excellent condition and immediately habitable. The sunny villa of about 600 square meters, optimally exposed, consists of a GROUND FLOOR with an elegant entrance, a large living room with frescoed ceilings and a marble fireplace, a dining area with an open kitchen and access to a large terrace with sea view, a small bathroom with bathtub, a bedroom, a double bedroom with en-suite bathroom, accessible both from the outside and from the entrance of the villa. A FIRST FLOOR: double bedroom with sea view and en-suite bathroom, bedroom with sea view and balcony, double bedroom with walk-in closet, windowed bathroom with shower. OUTBUILDING ON THE FIRST FLOOR: large living room with small bar area, double bedroom, bathroom with bathtub/shower. LOWER FLOOR: second outbuilding with independent access, consisting of a double bedroom, kitchenette and bathroom with shower. BASEMENT: further large living area with living room and dining area. EXTERIORS: Terraces equipped with relaxation and dining areas Panoramic view of the Gulf of La Spezia and the sea VILLA MARINASCO: a unique opportunity to experience the charm of Liguria in a historic residence with all modern comforts. Type: Villa Floors: 3 Commercial area: 600 m² Rooms: 20 Bathrooms: 6 Land area: 1,780 m² Terrace and balcony: Sea view Parking space: Included in the price Condition: Good Year of construction: 1910 Heating: Autonomous, natural gas Energy class: 175 kWh/m² year EQUIPMENT Garden: Private SPECIAL NOTES Excellent real estate investment ideal for being lived and enjoyed in every season of the year, even by large families, or to be put all or in part to inc', 'La Spezia', 'La Spezia', 'liguria', 'Variante Aurelia no number', 44.1290707, 9.7982275, 'https://www.idealista.it/immobile/30199963/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/10/1d/75/615765414.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/10/1d/75/615765414.webp"]', 62, 'villa', 'villa', 67.0, 95.0, 40.0, 60.0, 60.0, 59.0, 70.0, 1533.0, 'Pisa (PSA)', 69.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (56, '28592289', 320000.0, 1010.0, 18, 2, 'Casale/cascina in Regione Sorba, 6', 'South Piedmont, Cessole (AT): in a dominant position among the hills of Asti, among the most renowned for wine production (with particular reference to Moscato grape varieties), we offer for sale a well-preserved farmhouse with panoramic views. The property enjoys a strategic position: just 4 minutes from the town center, 25 minutes from Canelli and about 50 minutes from the renowned towns of Alba and Acqui Terme. An ideal location for those who want to live in the quiet of the countryside, without sacrificing the convenience of the main services and tourist attractions. The farmhouse is surrounded by land with a total area of over 46,000 square meters, of which over 20,000 square meters are cultivated with vineyards with Moscato and Chardonnay varieties. The remaining land is composed of meadows, woods and arable areas. The farm is ideal for those who want to develop an agricultural, agritourism project or simply live immersed in nature. The farmhouse is spread over a total area of over 1,000 square meters and consists of: Main house First Floor (180 sq m): entrance hall, kitchen with dining room, four bedrooms, bathroom, closet and balcony with panoramic view. Ground Floor: spacious tavern, bathroom, closet, cellars and large storage room. Basement: charming cellar with barrel vault in Langa Stone, ideal for aging wine. Adjacent agricultural building (on two levels) Ground Floor: storage rooms, shelter for tools and agricultural machinery, cellar and chicken coop. First Floor: large barn. The property is completed by a further adjacent building useful for agricultural activity or as a warehouse. This compendium represents a rare opportunity for those looking for large spaces and the possibility of living in an authentic and suggestive context, typical of the Piedmontese farming tradition. Also suitable for accommodation or agricultural activities.', 'Cessole', 'Asti', 'piemonte', 'Regione Sorba, 6', 44.6443222, 8.2337236, 'https://www.idealista.it/immobile/28592289/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/99/98/64/608635278.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/99/98/64/608635278.webp"]', 57, 'casalicascine', 'casale', 67.0, 100.0, 15.0, 80.0, 54.0, 58.0, 77.0, 317.0, 'Genova (GOA)', 54.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (57, '31318014', 180000.0, 435.0, 20, 4, 'Villa in Regione Montaldo, 117', 'We offer for sale a splendid independent villa of 435 sqm of living space, surrounded by a large private garden of 7000 sqm, ideal for enjoying moments of outdoor relaxation and the magnificent panorama. The property is divided into four independent apartments, each consisting of: Entrance into a spacious living area with fireplace, two bedrooms, and a bathroom. All apartments are in excellent condition, ready to be inhabited or for rental use. The property is completed by five garages, perfect for meeting the needs of multiple families or a tourist rental business. The privileged location offers a breathtaking view of Monviso, making this villa a unique opportunity, both as a primary residence and as an investment for the tourism sector. The rooms are in excellent condition and ready to be inhabited. The property is equipped with independent heating and is served by a convenient municipal road, ensuring easy access in all seasons.', 'Ponzone', 'Alessandria', 'piemonte', 'Regione Montaldo, 117', 44.5238581, 8.5130801, 'https://www.idealista.it/immobile/31318014/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/67/07/a5/694043983.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/67/07/a5/694043983.webp"]', 64, 'villa', 'villa', 67.0, 100.0, 15.0, 100.0, 54.0, 54.0, 74.0, 414.0, 'Genova (GOA)', 29.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (58, '31567422', 160000.0, 400.0, 17, 4, 'Semi-detached house in Sp210, 276', 'The view is breathtaking.. . the hamlet of Abasse is located 45 minutes from the Ligurian coast, and this independent villa, with its impeccable structure, is an excellent investment opportunity both as a primary residence and as a hospitality facility. Three apartments with generous spaces for a total of over 300sqm of living area, independent entrances, and panoramic views for all. The villa has a pleasant paved outdoor space with parking, low walls delimiting terraces for a vegetable garden, fruit trees, and a manageable garden of about 2000sqm. The property enjoys total privacy while being located in an inhabited hamlet served by a small mini-market, it has access from the provincial road, from which it is slightly set back.', 'Ponzone', 'Alessandria', 'piemonte', 'SP210, 276', 44.5471764, 8.5244953, 'https://www.idealista.it/immobile/31567422/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7e/89/93/658653489.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7e/89/93/658653489.webp"]', 46, 'semidetachedHouse', 'villa', 67.0, 100.0, 15.0, 100.0, 54.0, 53.0, 74.0, 400.0, 'Genova (GOA)', 29.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (59, '34373974', 230000.0, 148.0, 6, 2, 'Detached house in via Gabriele Rossetti no number', 'Period Palazzo with Panoramic Terraces in the Heart of Ostuni In the center of Ostuni, a few steps from Piazza della Libertà and the timeless charm of the White City, we find this elegant historic building on several levels, with double independent entrance, generous internal spaces and two splendid panoramic terraces with open views over the rooftops of the center and the sea in the distance. With a total area of approximately 160 square meters, the property retains its original architectural elements: stone vaults, period floors and balconies overlooking the characteristic Ostuni alleys. The main entrance leads to a large living room with star vaulted ceilings and a balcony overlooking the outside. Following this, we find a kitchen with a fireplace and direct access to the balcony, two bedrooms, one of which overlooks the interior, and a full bathroom. An internal staircase connects to the upper floor, where a bright room opens onto the first panoramic terrace, as well as a second bathroom and a space perfect as a study or additional bedroom. On the lower floor, with independent entrance from the side street, there is a storage area with ancient exposed stone vaults, ideal for creating an independent environment for receptive use or a relaxation area. Main features: Two panoramic terraces with views of the city and a glimpse of the sea Star and barrel vaults in excellent condition Wooden window frames and authentic architectural details Autonomous utilities and double access Central and well-served area, a few minutes walk from all the main points of interest The property, while requiring restoration work, represents a rare opportunity for those who wish to experience the authenticity of the historic center of Ostuni or invest in a structure with great tourist potential, in the heart of one of the most loved destinations in Puglia. Points of interest: The Municipality of Ostuni is part of the province of Brindisi and is located in the Altosalento area, about 7 km ', 'Ostuni', 'Brindisi', 'puglia', 'via Gabriele Rossetti no number', 40.7257571, 17.5802136, 'https://www.idealista.it/immobile/34373974/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/d1/a5/b4/753175748.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/d1/a5/b4/753175748.webp"]', 37, 'independantHouse', 'palazzo', 66.0, 20.0, 40.0, 60.0, 92.0, 72.0, 92.0, 1554.0, 'Bari (BRI)', 83.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (60, '33315297', 2300000.0, 2380.0, 12, 3, 'Estate in via della Centrale no number', '**Farmhouse for Sale in the Heart of Valdarno** Discover a unique opportunity with this charming farmhouse located in the heart of Valdarno, a farm that extends over 75 hectares of land, surrounded by woods and pastures. This solution offers three residential buildings to be renovated, warehouses, storage areas, two barns, and stables, perfect for those who wish to start an agricultural business or simply enjoy the tranquility of the Tuscan countryside. Access is easy thanks to an asphalt road, with the last part of a dirt road leading to this corner of paradise. Just 10 minutes from all services, it is the ideal place for those seeking a balance between rural life and modern conveniences. Furthermore, the farm is enriched by an artificial lake and borders the Lake of the Dam, offering a breathtaking panorama and opportunities for outdoor activities. With a total area of approximately 2,380 m², this farm represents a blank canvas for those who wish to customize the spaces according to their needs. The presence of a photovoltaic system in the warehouse contributes to making this property even more interesting from an energy point of view. Don''t miss the opportunity to transform this place into an exclusive retreat!', 'Civitella in Val di Chiana', 'Arezzo', 'toscana', 'via della Centrale no number', 43.4853638, 11.7297329, 'https://www.idealista.it/immobile/33315297/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/22/ae/24/713668753.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/22/ae/24/713668753.webp"]', 63, 'countryHouse', 'farmhouse', 66.0, 100.0, 40.0, 80.0, 64.0, 49.0, 58.0, 966.0, 'Firenze (FLR)', 56.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (61, '32463421', 625000.0, 384.0, 11, 4, 'Casale/cascina in località Petrognano, 58', 'In a panoramic position and immersed in the green Tuscan hills, Domina Immobiliare exclusively presents a fascinating real estate complex located in Rufina, in the Petrognano area. The property is located in a private and quiet area, ideal for those who wish to live immersed in the tranquility of nature, without sacrificing convenience: access is simple and well-connected, making every movement easy and fast. The interior spaces are distinguished by their large and well-distributed surfaces, designed to guarantee comfort and functionality in every environment, both in the living areas and in the sleeping area. Outside, the land surrounding the property is productive and carefully maintained, perfect for both agricultural activities and for those who want a large green space to live in, cultivate, or simply enjoy in the open air. The property consists of three real estate units. Single-family building (A) Arranged on three levels (basement, ground floor and first floor), with ample interior and exterior spaces. Ground Floor (122 sq m - 90 sq m usable): living room, kitchen, dining area, bathroom, terrace and large private garden. First Floor (122 sq m - 93 sq m usable): four double bedrooms, service bathroom and storage room. Basement (94 sq m - 75 sq m usable): accessory rooms such as storage room, workshop, cellar, woodshed and oven. External annexes (24 sq m - 19 sq m usable): loggia and two warehouses. 30 sq m canopy: used as storage for tractors and agricultural equipment. Two-family building (B) Two apartments with independent entrances, distributed over two floors, both with a garden. Apartment B1 (Ground Floor 70 sq m / 40 sq m usable): double bedroom, kitchen-living room, bathroom and storage room. Apartment B2 (First Floor 70 sq m / 46 sq m usable): double bedroom, kitchen-living room, bathroom, storage room, plus a loft, a roof window designed for a telescope and a private garden. External annex (5 sq m): technical room and warehouse. The property is surro', 'Rufina', 'Firenze', 'toscana', 'località Petrognano, 58', 43.8277173, 11.5356286, 'https://www.idealista.it/immobile/32463421/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/72/c7/8e/685004367.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/72/c7/8e/685004367.webp"]', 144, 'casalicascine', 'casale', 66.0, 76.0, 40.0, 100.0, 64.0, 59.0, 67.0, 1628.0, 'Firenze (FLR)', 27.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (62, '32826210', 285000.0, 290.0, 12, 3, 'Villa in via Giuseppe Mazzini', 'Posada, a pretty village with character, perched on top of an ancient hill dominated by the remains of a castle-fortress shrouded in legend, plenty of wonderful beaches and evocative medieval atmospheres at just a few steps to the beach: capital of the Baronia area, halfway between Gallura and Barbagia and at just few minutes to La Caletta, Siniscola and Budoni; Posada with its dream beaches has become part of the locations awarded with the Cinque Vele 2023. In this privileged context, where the pace is slow and you can enjoy walking in the little streets of the old town discovering the surrounding beauty, where the simplicity of the landscape with its verdant crystalline sea is enriched with typical traditional dishes and excellent local wines, in this place where there is still much to discover, we offer for sale this completely independent villa surrounded by a large plot of over 1,000 square meters, with excellent exposure, in a quiet area still at few steps from all the amenities and at few minutes to the beach. The villa, with access from a private road, is on two levels and consists of two completely independent apartments in need of some renovation and modernization works, with excellent potential, perfect for families or as an investment for holiday lettings, due also to the possibility of being able to enlarge it. Each apartment has a large and luminous living room, three spacious bedrooms, kitchen/dining room, hallway, kitchenette, bathroom and two verandas. Despite requiring some renovation works this villa has extraordinary potential to become your dream home or an excellent investment opportunity.', 'Posada', 'Nuoro', 'sardegna', 'via Giuseppe Mazzini', 40.6298671, 9.7151234, 'https://www.idealista.it/immobile/32826210/', 'https://img4.idealista.it/blur/480_360_mq/90/id.pro.it.image.master/82/90/bd/696288021.webp', '["https://img4.idealista.it/blur/480_360_mq/90/id.pro.it.image.master/82/90/bd/696288021.webp"]', 45, 'villa', 'villa', 66.0, 95.0, 40.0, 80.0, 56.0, 47.0, 72.0, 983.0, 'Olbia (OLB)', 34.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (63, '34048895', 171750.0, 412.0, 9, 5, 'Detached house in corso Repubblica no number', 'Corso Repubblica, 08020 Orune NU The main residential building is spread over two floors above ground and consists on the ground floor of an entrance/staircase, kitchen, living room, hallway, dining room, bathroom, closet, additional internal courtyard, and boiler room. On the first floor there is a hallway, two bathrooms, four bedrooms, a balcony facing the street, and a second balcony that gives access to a large terrace. On the ground floor, with separate access from the main courtyard, there is, as mentioned, a rustic kitchen with a bathroom and closet, as well as a shed used as a tool shed. The second building is on one level and consists of a rustic kitchen, bathroom, and closet. Judicial Auction - A.P.I. Srl Reference 84.2024.260526 NUORO This is a Judicial Sale with the Assistance of A.P.I. Srl, a reference studio for acquisitions of properties in Judicial Auctions and pre-auction purchases. Address the real estate enforcement market, following the correct legal protocol. ____________________________________________________ INSURANCE POLICY "The property is insurable in Judicial Auction" - Purchase by insuring your property, ask for a quote for an insurance policy against theft and damage from the best companies in contact with our firm, who will be able to provide the best solutions. ____________________________________________________ ASTE PREASTE INVESTIMENTI srl We operate with our clients in a totally personalized way, our professionals are regularly registered, licensed to practice the profession, not simple collaborators, but Authorized Consultants and Attorneys who can accompany you and allow you to achieve the goals you have "set for yourselves". They will be with you from the initial stages until the delivery of the property and will be your point of reference for any aspect related to the purchase and management of the asset. Strength, Courtesy, Professionalism, Experience, Solidity, Transparency are just some of our characteristics and we are cer', 'Orune', 'Nuoro', 'sardegna', 'corso Repubblica no number', 40.4093618, 9.3698223, 'https://www.idealista.it/immobile/34048895/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/d9/75/ff/775574816.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/d9/75/ff/775574816.webp"]', 36, 'independantHouse', 'house', 66.0, 100.0, 40.0, 80.0, 56.0, 42.0, 68.0, 417.0, 'Olbia (OLB)', 56.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (64, '34772829', 115000.0, 237.0, 10, 2, 'Detached house in via Portico', 'Discover this charming town house in the heart of Cuglieri, a true gem at just 20 minutes to the crystal-clear sea of Bosa and 15 minutes to the enchanting golden beaches of Santa Caterina di Pittinuri, S''Archittu, and Torre del Pozzo. The strategic location allows quick access to the most beautiful beaches on Sardinia''s western coast, while its proximity to main facilities makes everyday life really easy. This renovated home offers an elegant and welcoming atmosphere, spacious and well-lit, perfect for those seeking comfort and tranquility. Nestled in a peculiar historical setting with character, the house, thanks to its exposure, enjoys natural light, making every room unique. The ground floor features a large living room with kitchen area, while the raised ground floor has a welcoming and spacious bedroom, a single bedroom, a hallway, and a new and comfortable, highly functional bathroom. The second floor is composed of a second living room with kitchen area and fireplace, a delightful balcony, a hallway, and two bedrooms, one with a large balcony. On the third floor, there''s a spacious and brand-new attic, perfect as a relax area, study, or private suite. It has a large panoramic terrace offering amazing views over the town and the sea, a hallway, and a newly built bathroom. A basement level with a secondary entrance and two large cellar rooms add further usable space to the home. This home, with its high potential, is perfect as both a primary residence and a holiday home. The home is air-conditioned and furnished, making it ready to move-in. Don''t miss the chance to live in a place where history and beauty meet.', 'Cuglieri', 'Oristano', 'sardegna', 'via Portico', 40.1900033, 8.5682317, 'https://www.idealista.it/immobile/34772829/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/50/93/1f/768516122.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/50/93/1f/768516122.webp"]', 49, 'independantHouse', 'torre', 66.0, 100.0, 40.0, 40.0, 56.0, 67.0, 67.0, 485.0, 'Cagliari (CAG)', 112.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (65, '35048806', 385000.0, 403.0, 5, 2, 'Villa in via Cerro, 34', 'SESTOLA, High Modenese Apennines. So, let''s start with one thing: this house doesn''t make itself easy to find. It plays hard to get. The diva. The one that says, "If you want me, you''ll look for me." And there you are, following the path, thinking, "Where on earth is Lucie taking me this time" Then you turn the corner and… bam. A panorama that knocks you flat. Mountains, hills, valleys, and that silence that seems made just to make you say, "Okay, I''m stopping here and not going back down." La Casa del Sentiero Segreto (The Secret Path House) is like that: a little shy, a little mysterious, a little "I don''t show myself to everyone." But when it decides to reveal itself… oh my. Our mountains are jealous, as you know. They hide beautiful things like certain grandmothers who keep the good cookies in the high cupboard. And you have to be curious enough, stubborn enough, enough… yourself, to find them. And here comes the funny part: despite all this "secret place" charm, you arrive comfortably. Two roads, one from Fanano and one from the provincial road. No extreme trekking, no ropes, no sherpas. Just you, the car, and a hundred meters later… a panorama that makes you want to call someone and say, "You''ll never believe where I''ve ended up." Around the house, there are fields, oak woods, light to spare. Here the sun arrives early and leaves late, like a guest who no longer wants to go home. And honestly, I understand. The name? It comes from an old owner who used to cycle everywhere before flying off to Australia. A nice guy, apparently. And he didn''t lack space: 87,000 sqm. Yes, you read that right. Eighty-seven thousand. Practically, if you get lost in the woods, you can blame yourself, not the property. The estate is a small village: – the new and bright ranch – the chicken coop with the bread and pizza oven (which alone is worth the trip) – the well – and the old farmhouse that is now more poetry than masonry The ranch, finished in 2010, is the beating heart. You ent', 'Sestola', 'Modena', 'emilia-romagna', 'via Cerro, 34', 44.2593396, 10.8541928, 'https://www.idealista.it/immobile/35048806/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/42/71/96/778668463.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/42/71/96/778668463.webp"]', 93, 'villa', 'farmhouse', 66.0, 90.0, 40.0, 80.0, 56.0, 52.0, 72.0, 955.0, 'Bologna (BLQ)', 46.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (66, '34239296', 198000.0, 318.0, 10, 2, 'Semi-detached house in via della Resistenza, 10', 'In Masiera di Bagnacavallo, we present an independent two-family solution, consisting of two independent portions with separate entrances. An ideal solution for those looking for two distinct units, perfect for families, extended families, or those who want a home with double independence. The two portions, respectively of 117 m² and 160 m², are distributed on two levels and require only small modernization works. On the ground floor you will find the independent entrances, garage and common areas, while on the respective upper floors the main rooms of the house are developed: kitchen, living room, dining room, bedrooms and bathrooms, with balconies accessible from several rooms. To complete the property there is a large garden of about 550 m², perfect for leisure, for those who love greenery or to create an outdoor relaxation area. There are also numerous services and accessory areas, which add functionality and possibilities of use. A versatile and rich in potential proposal, located in a central position, convenient to all services and close to Bagnacavallo and Fusignano. Asking price € 198,000 For more information search for reference 2262 on Call now to arrange your visit, we look forward to showing you your new home!', 'Bagnacavallo', 'Ravenna', 'emilia-romagna', 'via della Resistenza, 10', 44.4608162, 11.9673109, 'https://www.idealista.it/immobile/34239296/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/42/00/90/746638453.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/42/00/90/746638453.webp"]', 54, 'semidetachedHouse', 'house', 66.0, 100.0, 40.0, 80.0, 56.0, 43.0, 67.0, 623.0, 'Bologna (BLQ)', 54.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (67, '30616138', 107000.0, 197.0, 7, 2, 'Detached house in via Rocca D''Arazzo', 'Charming Detached Country Home with Characterful Rustico and Expansive Views Tucked away in a truly enchanting spot just a few kilometres from Montegrosso d’Asti, heading towards Rocca d’Arazzo, this delightful property captures all the charm of the Piedmontese countryside. The main house, lovingly restored, welcomes you with a generous eat-in kitchen, a cosy living room, a bathroom, and an additional room on the ground floor with direct access to the courtyard—perfect for those who love indoor-outdoor living. Upstairs, you''ll find three bedrooms and a second bathroom, all with lovely views and warm, traditional touches. Across the courtyard stands the old rustico, still untouched and ready to be brought back to life. It spans three spacious rooms—one per level—offering ample potential for a guesthouse, studio, or atelier. A traditional brick-vaulted cellar lies beneath, still preserving the old tools once used for winemaking. At street level, a convenient garage adds functionality, while just in front of the rustico, a small orchard and vegetable garden provide a tranquil green corner. The property also includes 21,730 sqm of land, formerly vineyards, now partly meadow, arable, and woodland—ideal for nature lovers or those dreaming of a return to the land. Please note: the kitchen furniture and pellet stoves are not included in the asking price, but may be negotiated separately should the buyer be interested.', 'Montegrosso d''Asti', 'Asti', 'piemonte', 'via Rocca D''Arazzo', 44.834057, 8.2518439, 'https://www.idealista.it/immobile/30616138/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/93/e4/cd/771873586.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/93/e4/cd/771873586.webp"]', 51, 'independantHouse', 'rustico', 66.0, 100.0, 15.0, 60.0, 72.0, 60.0, 63.0, 543.0, 'Torino (TRN)', 62.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (68, '34146712', 2190000.0, 1600.0, 30, 3, 'Villa in via Torricella no number', 'SAN MARTINO, CAMPI BISENZIO, Villa for sale of 1600 Sq. mt. , Be restored, Heating Individual heating system, Energetic class: G, placed at Ground on 3, composed by: 30 Rooms, Separate kitchen 20 Bedrooms, 3 Bathrooms, Parking space, Garden, Price: € 2,190, 000.', 'Campi Bisenzio', 'Firenze', 'toscana', 'via Torricella no number', 43.8116977, 11.129574, 'https://www.idealista.it/immobile/34146712/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/68/9b/92/743072729.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/68/9b/92/743072729.webp"]', 40, 'villa', 'villa', 65.0, 88.0, 40.0, 100.0, 64.0, 50.0, 58.0, 1369.0, 'Firenze (FLR)', 6.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (69, '32137510', 1500000.0, 750.0, 30, 12, 'Estate in via Armando Diaz Donnini', 'REGGELLO, NEARBY. This property, restored with quality materials, is located in a hillside location with excellent sun exposure, surrounded by olive trees and vineyards and boasting 360-degree views. Typical Tuscan architecture, the property is accessed via a private road lined with beautiful cypress trees. The property comprises two residential units, sharing a private pool and land. THE BARN Finely renovated in noble Tuscan style with fine materials such as the bedroom floors made from specially crafted barrel doge and in the living area with floors in fine handmade terracotta, the bathrooms with selected Vietri ceramics, arranged on two levels plus cellar, it consists of: a large loggia where in front we find the old peasant farmyard paved with original stones, fenced garden and view of the access road with cypress trees, on the ground floor: we find a room with billiards, living room, wonderful very bright built-in kitchen furnished with excellent taste with fireplace, double bedroom with bathroom and service bathroom on the upper floor accessed by means of a beautiful decorative staircase in wrought iron made by a local craftsman and custom-built wood, you access where we find two double bedrooms, bathroom with shower living room with very characteristic arched windows. THE FARMHOUSE Completely restored currently used for tourist accommodation, it is built in a horseshoe shape and is on two levels and consists of a large common living area, where we find an industrial-equipped kitchen, a huge fireplace and 2 service bathrooms, the house is arranged in several residential units divided as follows on the ground floor, two units, the first with a living room, kitchen and two bedrooms, two bathrooms and a small cellar and another two-room apartment with bathroom also on the ground floor we find a room with external access with laundry for guests of the farmhouse, access to the first floor is via a characteristic stone staircase there we find two residential units, ', 'Reggello', 'Firenze', 'toscana', 'via Armando Diaz Donnini', 43.732309, 11.499085, 'https://www.idealista.it/immobile/32137510/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a7/99/ae/674590652.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a7/99/ae/674590652.webp"]', 50, 'countryHouse', 'farmhouse', 65.0, 59.0, 40.0, 100.0, 64.0, 76.0, 66.0, 2000.0, 'Firenze (FLR)', 25.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (70, '34905533', 168000.0, 120.0, 4, 1, 'Detached house in Teviggio, 32', '**Independent House for Sale: A Haven of Elegance and Comfort** Discover this splendid independent house located in a hilly position, immersed in the nature of Val di Vara and far from the city chaos. With a fenced garden of 400 square meters equipped with every comfort, this outdoor space is ideal for relaxing or having fun with friends and family. Renovated and tastefully furnished, the house is ready to be inhabited without further work, offering a perfect balance between elegance and functionality. Inside, a bright living room opens onto the kitchen, creating a welcoming and convivial atmosphere. The house has three double bedrooms, perfect for accommodating the whole family. The bathroom is equipped with a modern shower, while two windowed storage rooms and a cellar offer additional storage space. Convenient access for people with reduced mobility makes this property suitable for everyone. The wood and LPG heating system ensures optimal comfort in every season, allowing you to enjoy the house at any time of the year. With a total of 120 m² of commercial space spread over 4 rooms, this house is an unmissable opportunity for those seeking a home that combines style and practicality in a unique natural setting. Don''t miss the chance to visit it!', 'Varese Ligure', 'La Spezia', 'liguria', 'Teviggio, 32', 44.36548, 9.621643, 'https://www.idealista.it/immobile/34905533/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/32/e9/d7/773458795.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/32/e9/d7/773458795.webp"]', 31, 'independantHouse', 'house', 65.0, 100.0, 40.0, 60.0, 60.0, 42.0, 67.0, 1400.0, 'Genova (GOA)', 63.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (71, '30292629', 298000.0, 302.0, 12, 3, 'Villa', 'Welcome to Flussio, a pretty village on the central western coast of Sardinia, at just 10 minutes to the crystal clear sea and the picturesque town of Bosa and 50 minutes to Alghero. An old village where people pick the asphodel, the raw material to make the typical local baskets, called canestri: this small center owes its fame mainly to the art of weaving, but is also known for the production of an excellent Malvasia. In a truly privileged panoramic and quiet location, just outside the small village, without passage of cars, we offer for sale this wonderful recently built villa, built with top quality materials, welcoming, spacious and luminous with a private garden where it is possible to have several parking spaces; the villa has on the ground floor a large living area, dining room with kitchen area, storage and bathroom made with quality materials and sanitary fittings of excellent functionality; the living area is enriched by the splendid staircase with great aesthetic impact, made of "Biancone di Orosei" marble, which leads to the first floor where there are five large and comfortable bedrooms, a spacious hallway, bathroom and a beautiful terrace from which you can enjoy an enchanting view over the sea and the surrounding countryside. The villa also includes an apartment on the second floor reachable through an external staircase and therefore completely independent from the main house, consisting of a dining room, bedroom, bathroom and large terrace, ideal for guests or as an additional private space. This villa represents a unique opportunity for those who want a simple and quiet life, perfect for those who love to live in a peaceful environment, surrounded by nature but with all modern comforts. The house needs some external works to finish and tidy up the garden.', 'Flussio', 'Oristano', 'sardegna', 'Flussio', 40.2689373, 8.5411742, 'https://www.idealista.it/immobile/30292629/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e0/d8/2e/618669061.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e0/d8/2e/618669061.webp"]', 46, 'villa', 'villa', 65.0, 95.0, 40.0, 40.0, 56.0, 53.0, 74.0, 987.0, 'Olbia (OLB)', 108.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (72, '34623202', 29500.0, 165.0, 4, 2, 'Villa in via Vittorio Veneto no number', 'GONNOSTRAMATZA – VIA VITTORIO VENETO - Detached house with private courtyard and Sardinian tradition details In the center of the town of Gonnostramatza, in the province of Oristano, we offer for sale a spacious detached house to be renovated, ideal for those who wish to create a personalized home while maintaining the charm of traditional dwellings. The property, a typical local manor house, preserves authentic traditional elements such as the internal fireplace and the wood-fired oven in the courtyard, features that make the property particularly evocative and rich in history. Surface area and space distribution The house is spread over two levels for a total area of approximately 165 sq m, of which 143.39 sq m are for living space, plus various accessory rooms. Ground floor – approximately 83 sq m Entrance with hallway Two large rooms Further hallway Kitchen Bathroom Completing the floor: Private internal courtyard Covered canopy Traditional outdoor wood-fired oven Storage room Closet / storage room First floor – approximately 60 sq m Two bedrooms Hallway Bathroom Thanks to its complete independence, generous dimensions, and the presence of functional outdoor spaces, the property represents an interesting solution both as a primary residence and as an investment for creating a holiday home or a small accommodation facility. An opportunity to enhance a house with an authentic character and transform it into a welcoming residence in the tranquil setting of the town.', 'Gonnostramatza', 'Oristano', 'sardegna', 'via Vittorio Veneto no number', 39.6822703, 8.834012, 'https://www.idealista.it/immobile/34623202/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7c/28/3a/780568979.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7c/28/3a/780568979.webp"]', 26, 'villa', 'villa', 65.0, 100.0, 40.0, 80.0, 56.0, 50.0, 59.0, 179.0, 'Cagliari (CAG)', 51.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (73, '28989570', 138000.0, 269.0, 5, 2, 'Semi-detached house in Vie Fiorini no number', 'TWO-FAMILY villa just 300 meters from the center of Copparo. A) The 183 m2 house consists of an entrance hall with utility room/boiler room, living room with fireplace, kitchen with pantry, dressing room and bathroom and also a windowed laundry/storage room. On the first floor there are 3 double bedrooms, 1 large anteroom/wardrobe and a large bathroom with bathtub and double and double sinks. The garage equipped with an overhead door with pedestrian door is connected to the house. The house was completely renovated in 1989 B) Adjacent to this unit there is a second independent unit of 67 m2 to be modernized, which can be combined with the main house to create a single home. This second unit has a living room, a kitchenette, a small bathroom on the ground floor, while on the first floor there is a double bedroom and a study. A) NOTES MAIN HOUSE The house is in a good state of maintenance Wooden window frames with double glazing Wooden shutters Parquet floors in the sleeping area Automated driveway gate. Part of the courtyard is also used by the neighbor to access their home.', 'Copparo', 'Ferrara', 'emilia-romagna', 'Vie Fiorini no number', 44.8910641, 11.8277056, 'https://www.idealista.it/immobile/28989570/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ac/ab/c2/574609390.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ac/ab/c2/574609390.webp"]', 39, 'semidetachedHouse', 'villa', 65.0, 100.0, 40.0, 80.0, 56.0, 51.0, 59.0, 513.0, 'Bologna (BLQ)', 58.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (74, '32649617', 130000.0, 1189.0, 20, 3, 'Casale/cascina in Sp210, 65', 'Historic Estate for Sale - A Unique Opportunity! Discover this charming 22,000 sqm estate, a corner of paradise perfect for those who wish to start a hospitality business such as an agriturismo, B&B, or farm. The 428 sqm manor house offers ample interior spaces, with 20 well-distributed rooms, three bathrooms, and a terrace that offers breathtaking views of the surrounding landscape. The property is equipped with 761 sqm of technical rooms and warehouses, ideal for managing commercial activities. The stable, already connected to the aqueduct and natural gas, represents an additional added value for those who wish to undertake an agricultural business. The strategic location, close to the provincial road, guarantees excellent visibility for the resale of local products. With the possibility of creating a second independent access, this estate offers infinite development opportunities. The manicured garden and garage complete this unmissable offer. Don''t miss the opportunity to invest in a property with great potential! Contact us for more information and to arrange a visit!', 'Ponzone', 'Alessandria', 'piemonte', 'SP210, 65', 44.5317822, 8.5332178, 'https://www.idealista.it/immobile/32649617/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b2/73/5a/690860856.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b2/73/5a/690860856.webp"]', 59, 'casalicascine', 'casale', 65.0, 100.0, 15.0, 100.0, 54.0, 60.0, 60.0, 109.0, 'Genova (GOA)', 28.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (75, '34895313', 360000.0, 390.0, 6, 3, 'Villa in strada della Vela, 105', 'We offer for sale an elegant, completely INDEPENDENT villa, located on a quiet side street of Via Fanelli, in a residential and well-served area, as well as being in a phase of strong expansion. In the immediate vicinity are the terminus of bus line no. 21 and the Rossotono supermarket, making the location even more convenient and strategic for daily life. The property, dating back to the late 1980s, is spread over THREE floors and is in good general condition. The property is enhanced by a large and private GARDEN of approximately 900 sqm. It is composed as follows: RAISED GROUND FLOOR: (approx. 90 sqm) ENTRANCE to a bright LIVING ROOM, EAT-IN KITCHEN, STUDY, BATHROOM, and a large BALCONY on four sides, which provides natural light and continuity between interior and exterior. FIRST FLOOR: (approx. 90 sqm) FOUR BEDROOMS, TWO BATHROOMS, plus FOUR well-distributed BALCONIES. TERRACE: (approx. 110 sqm) Large overlying flat roof. BASEMENT FLOOR: (approx. 120 sqm) Cozy TAVERN divided into two rooms, plus a boiler room, storage rooms, and a perimeter crawl space that ensures insulation and protection. PRIVATE GARDEN: (approx. 900 sqm) the villa is surrounded on all sides by a large planted garden, equipped with a covered pergola for car parking, an area for firewood, and ideal spaces for enjoying the outdoors in complete privacy. It features: Independent gas heating, air conditioning system, security gates, satellite dish, water reserve, mosquito nets, English-style interior doors, sewage connection already made. THE VILLA CAN EASILY BE DIVIDED INTO TWO INDEPENDENT HOUSING UNITS and is ideal for those seeking independence, green spaces, and tranquility without giving up services. Although already in good condition and immediately habitable, the property requires some modernization to fully enhance its potential.', 'Bari', 'Bari', 'puglia', 'strada della Vela, 105', 41.077092, 16.8826693, 'https://www.idealista.it/immobile/34895313/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f8/d4/03/773083443.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f8/d4/03/773083443.webp"]', 19, 'villa', 'villa', 64.0, 73.0, 40.0, 100.0, 60.0, 49.0, 68.0, 923.0, 'Bari (BRI)', 12.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (76, '33655167', 120000.0, 120.0, 3, 2, 'Casale/cascina in via Spine Rossine', '**Farmhouse for Sale in Magical Puglia - Putignano (BA)** Discover this charming stone farmhouse, nestled in the beautiful Apulian countryside, just minutes from the center of Putignano. In a quiet hilly area, along the picturesque Via Spine Rossine, stands this charming stone farmhouse, immersed in the tranquility and colors of the countryside. A property with an authentic flavor, perfect for those looking for a place to transform, where to live or invest in harmony with nature and tradition. The main body of the property is spread over a single level of approximately 90 square meters, with rooms characterized by vaulted ceilings up to 4 meters high, antique local stone floors and stone fireplaces that tell stories of a bygone era. Every corner conveys the rustic charm of country houses, offering an ideal setting for those who want to renovate while maintaining the original style. Outside, a plot of approximately 5,000 square meters surrounds the house, planted with olive trees and fruit trees, and represents a valuable space for those who dream of a lush garden, a vegetable garden, a swimming pool or simply a quiet refuge where to relax away from the city chaos. The stone property consists of a large kitchen, three rooms with services. There are already cisterns for collecting rainwater and electricity connection, while the septic tank is to be built. There is no heating system, but precisely for this reason the house lends itself to a complete customization, leaving full freedom in the design of spaces and systems. The farmhouse is located in a private but not isolated position, with direct access from a private avenue. The area is well connected and easily accessible, ideal for those looking for a main residence, a second home surrounded by greenery or a rural hospitality project. With an investment of €120,000, this property represents, close to tourist centers such as Alberobello and Castellana Grotte and the beaches of Monopoli and Polignano a Mare, a real op', 'Putignano', 'Bari', 'puglia', 'via Spine Rossine', 40.8555686, 17.1192369, 'https://www.idealista.it/immobile/33655167/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b9/71/51/726312821.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b9/71/51/726312821.webp"]', 27, 'casalicascine', 'casale', 64.0, 67.0, 40.0, 80.0, 60.0, 77.0, 63.0, 1000.0, 'Bari (BRI)', 44.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (77, '31529088', 48055.0, 112.0, 5, 3, 'Terraced house in largo Imperatore Costantino, 19 -18', 'Judicial Auction - A.P.I. Srl Reference 451.2016.060526 FOGGIA This is a Judicial Sale with the Assistance of A.P.I. Srl, a reference studio for acquisitions of properties in Judicial Auctions and Pre-Auction purchases. Address the Real Estate Enforcement market, following the correct Legal protocol. ____________________________________________________ LOCATION Via Padula 28 – CERIGNOLA (FG) Terraced single-family villa; for residential use on the first and second floors with an attached ground floor and exclusive courtyard, basement storage room on the first basement level located in Cerignola at Via Padula n. 28. Lot 2, internal 4, San Matteo District. The property in question is part of a series of terraced houses; it is a villa for residential use on the first and second floors with an attached ground floor registered as a garage and storage room on the first basement level, composed on the first floor of a dining room with kitchen, bathroom, closet, and balcony; on the second floor, a hallway, bedroom, dressing room/walk-in closet, second bedroom, bathroom, and two balconies; on the ground floor, a habitable kitchen, bathroom, and an attached uncovered area to the side and rear; on the first basement level, it consists of a single large room and a storage room created under the stairs, all connected by an internal staircase. ____________________________________________________ INSURANCE POLICY "The property is insurable in Judicial Auction" - Buy by insuring your property, ask for a quote for an insurance policy against theft and damage from the best Companies in contact with our studio, who will be able to provide the best solutions. ____________________________________________________ ASTE PREASTE INVESTIMENTI srl We work with our clients in a totally personalized way, our professionals are regularly registered, qualified to practice the profession, not simple collaborators, but Delegated Procurator Consultants who can accompany you and allow you to achieve t', 'Cerignola', 'Foggia', 'puglia', 'largo Imperatore Costantino, 19 -18', 41.2658023, 15.8935933, 'https://www.idealista.it/immobile/31529088/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/91/a9/54/779924519.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/91/a9/54/779924519.webp"]', 32, 'terracedHouse', 'villa', 64.0, 100.0, 40.0, 60.0, 60.0, 51.0, 59.0, 429.0, 'Bari (BRI)', 74.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (78, '32865090', 1500000.0, 750.0, 10, 8, 'Casale/cascina in strada Comunale Casole-Cavallano', 'In the splendid hills of Casole d''Elsa, with a breathtaking view of the surrounding landscape, we offer this beautiful stone farmhouse consisting of several real estate units, which make this small village a unique and charming object. With an area of approximately 750 square meters, the property is currently divided into 8 small independent apartments where a well-established accommodation business is carried out. The structure has been completely and finely restored in typical Tuscan style, with wooden beams, terracotta tiles and stone. Easily transformable into a private residence, the Property can be represented by a main building and some outbuildings to receive and welcome guests. The recently renovated swimming pool has a 360° view of the surrounding landscape and allows you to relax in this oasis of absolute privacy and tranquility. The surrounding greenery is also beautiful, with an extension of approximately 1 hectare, embellished with splendid manicured gardens, with flowers and native plants. The outdoor spaces are well equipped and cared for, for pleasant convivial moments outdoors. The town of Casole d''Elsa, famous for its Castle and its Etruscan origins, is located just 2 km from the structure, which can be reached by following a short dirt road of about 1.5 km. Volterra, Siena, Florence, the sea coasts, are all easily reachable, less than an hour''s drive from our Property. Come and immerse yourself in this little paradise of Tuscany. For more information and to arrange a visit, ask at the Agency.', 'Casole d''Elsa', 'Siena', 'toscana', 'strada Comunale Casole-Cavallano', 43.3530446, 11.0316198, 'https://www.idealista.it/immobile/32865090/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/db/e0/01/697547174.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/db/e0/01/697547174.webp"]', 32, 'casalicascine', 'casale', 64.0, 59.0, 40.0, 80.0, 64.0, 80.0, 65.0, 2000.0, 'Firenze (FLR)', 53.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (79, '33281425', 399000.0, 262.0, 13, 3, 'Villa in località Cava, 54', '**Sale of a Charming Property in Lucignano (IT)** Discover this extraordinary property located just a short distance from Lucignano, nestled in the beautiful Tuscan countryside. With breathtaking views that stretch to the horizon, this is the ideal place for those who wish to live in harmony with nature. The property is divided into two units, one of 141 square meters and the other of 121 commercial square meters, developed on two levels. The large spaces on the ground floor offer endless possibilities for customization. The structure is already partially used as a craft workshop, making it perfect for those looking for a work and residence opportunity in a single solution. It also has two large annexes, respectively of 69 square meters and 90 square meters, ideal for being transformed into garages or additional work spaces. The entire property is completely fenced, guaranteeing privacy and security. Sold with land of relevance and the possibility of purchasing an additional 6 hectares approximately, this property offers ample space with 13 rooms and 3 bathrooms. Enjoy moments of relaxation on the terrace or balcony. Built in 1900 and maintained in good condition, this is an unmissable opportunity for those seeking a refuge in the Tuscan countryside. Don''t miss this unique opportunity!', 'Lucignano', 'Arezzo', 'toscana', 'località Cava, 54', 43.2817178, 11.7480626, 'https://www.idealista.it/immobile/33281425/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/22/d6/0e/712520238.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/22/d6/0e/712520238.webp"]', 62, 'villa', 'villa', 64.0, 81.0, 40.0, 60.0, 64.0, 51.0, 70.0, 1523.0, 'Firenze (FLR)', 73.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (80, '29458122', 540000.0, 240.0, 9, 3, 'Villa in viale 25 Aprile, 29', 'The property sells a bright and well-maintained villa, ideal for a family or for those who desire a prestigious residence located about 950 meters from the historic center of Sarzana and 5 km from the sea.  The recently built property consists of a triple living room (with fireplace), a spacious kitchen, 3 bedrooms, 2 bathrooms, a storage room, as well as a finished and refined attic divided into 2 large rooms, with windows on the facade and a large skylight.  The property also includes a spacious Garage / laundry room or 40 sqm outbuilding equipped for a bathroom and kitchen, a technical room for a possible pool system and boiler. Surrounding garden of 800 sqm enclosed in masonry with double gates. Excellent finishes, perimeter and interior alarm system, satellite system, and central vacuum system.  FOR MORE INFORMATION AND APPOINTMENTS.', 'Sarzana', 'La Spezia', 'liguria', 'viale 25 Aprile, 29', 44.0979542, 9.9717127, 'https://www.idealista.it/immobile/29458122/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a5/18/c4/712280294.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a5/18/c4/712280294.webp"]', 84, 'villa', 'villa', 64.0, 70.0, 40.0, 80.0, 60.0, 62.0, 68.0, 2250.0, 'Pisa (PSA)', 57.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (81, '28099568', 148000.0, 220.0, 9, 2, 'Villa in via emilio lussu', 'Sindia, in a quiet area, at few steps from all the facilities and at just 15 minutes to the beach and to Bosa, we sell this independent, luminous and spacious villa with a garden all around the building; the house is in good condition, comfortable and built with good quality materials and well kept over the years and composed on the basement of bathroom, garage, rustic kitchen and three cellars; ground floor: large and well-lit living room with veranda, kitchen/dining with fireplace, kitchenette, three bedrooms, bathroom and large covered verandas around the house overlooking the garden; oil central heating; well to water the garden. The house is immediately habitable, with utilities connected, furniture included.', 'Sindia', 'Nuoro', 'sardegna', 'via emilio lussu', 40.2918704, 8.6562356, 'https://www.idealista.it/immobile/28099568/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/12/b4/90/538704177.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/12/b4/90/538704177.webp"]', 50, 'villa', 'villa', 64.0, 100.0, 40.0, 60.0, 56.0, 54.0, 59.0, 673.0, 'Olbia (OLB)', 99.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (82, '35123854', 35000.0, 100.0, 3, 1, 'Detached house in via Filippo Corridoni, 1', 'Charming detached house in the historic centre of Bortigali, combining traditional Sardinian charm with the rare convenience of direct access to a public square, ensuring plenty of light and extremely easy parking right in front of the entrance. The house is spread over two well-organised levels: upon entering the ground floor, you are greeted by a spacious kitchen dominated by a typical fireplace, an element that gives character to the entire room. Next to the kitchen is a versatile room, currently used as a living room but perfect for use as a first bedroom, served by a functional bathroom and spacious hallway.  Going upstairs, the house reveals its most intimate and charming side: a large master bedroom featuring a wonderful sloping ceiling with exposed beams, creating a cosy and timeless atmosphere.  This property is the ideal solution for those seeking an authentic retreat in one of the island''s most characteristic villages, without sacrificing the convenience of amenities and freedom of movement.', 'Bortigali', 'Nuoro', 'sardegna', 'via Filippo Corridoni, 1', 40.281472, 8.833277, 'https://www.idealista.it/immobile/35123854/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f7/e0/84/780961848.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/f7/e0/84/780961848.webp"]', 28, 'independantHouse', 'villa', 64.0, 100.0, 40.0, 60.0, 56.0, 53.0, 59.0, 350.0, 'Olbia (OLB)', 90.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (83, '27812704', 230000.0, 230.0, 9, 3, 'Villa in via dei camaldolesi', 'Scano di Montiferro, Central Western Sardinia, very well looked after and welcoming village with character at the Montiferru feet, in a picturesque landscape where the gaze is lost between the blue of the sea and the green of the mountains, at only fifteen minutes away to the beach and to Bosa, in a peaceful setting with little car traffic, we sell this semi-detached house in excellent condition, immediately habitable, furnished with simple and classic taste; on the first floor the house has a large terrace of over 100 square meters with panoramic views, veranda, large and well-lit living room/sitting room, kitchen, bathroom, single bedroom and two double bedrooms; second floor: hallway, mezzanine with lounge, two double bedrooms, bathroom and storage; on the basement large cellar with kitchen area, bathroom, garage.', 'Scano di Montiferro', 'Oristano', 'sardegna', 'via dei camaldolesi', 40.2162899, 8.5889311, 'https://www.idealista.it/immobile/27812704/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/62/ca/ac/525400392.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/62/ca/ac/525400392.webp"]', 73, 'villa', 'villa', 64.0, 94.0, 40.0, 40.0, 56.0, 51.0, 73.0, 1000.0, 'Olbia (OLB)', 109.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (84, '31636241', 285000.0, 435.0, 8, 3, 'Semi-detached house in via Niccolò Paganini no number', 'In a secluded corner of the Parma countryside, there stands a rare property that combines independence, versatility, and an authentic connection with nature. A place where every meter tells stories of tranquility, comfort, and potential. Surrounded by 2000 square meters of private greenery, this two-family residence houses two independent apartments of 148 square meters and 169 square meters, ideal for accommodating multiple generations or for creating a custom home with spaces dedicated to work, wellness, or creativity. Natural light flows through spacious and well-distributed rooms, offering functional solutions for those seeking a home to live fully, without compromise. Every detail is designed to guarantee comfort and freedom. To complete the property, a TWO-LEVEL STORAGE UNIT of 150 square meters: a multi-purpose space to be transformed into a workshop, hobby area, warehouse, or studio. A valuable extension for those who need more than just a house. The garden that embraces the property is a regenerating refuge, perfect for spending relaxing moments, creating a vegetable garden, organizing outdoor dinners, or building a play area for children. This is where nature and daily life meet. LIVING IN TRECASALI MEANS REDISCOVERING THE PLEASURE OF TIME, WITHOUT SACRIFICING CONVENIENCE A strategic location, easily connected to the main centers, allows you to enjoy the best of country life with the convenience of the city within easy reach. This property is not just a house: it''s a lifestyle choice, a unique opportunity for those who want to live in an authentic place, with space to be shaped according to their needs and desires. Contact us today via WhatsApp with the code PARMA683 to book a visit: it could be the home you''ve always dreamed of.', 'Sissa Trecasali', 'Parma', 'emilia-romagna', 'via Niccolò Paganini no number', 44.91055, 10.2637913, 'https://www.idealista.it/immobile/31636241/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/17/f9/a8/675949122.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/17/f9/a8/675949122.webp"]', 64, 'semidetachedHouse', 'house', 64.0, 100.0, 40.0, 60.0, 56.0, 42.0, 67.0, 655.0, 'Bologna (BLQ)', 91.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (85, '33883920', 790000.0, 750.0, 25, 5, 'Villa in via Vignolese', 'SPILAMBERTO" PROVINCE OF MODENA ART NOUVEAU VILLA - EARLY 1900S - ELEGANT - THREE-FAMILY - GARDEN - PARKING SPACES AND GARAGE A unique and elegant residence is now available for purchase. It extends over three floors, plus a basement and roof terrace, for a total area of approximately 690 square meters. It is surrounded by a private courtyard of 1,400 square meters, partly used as a courtyard area and partly as a landscaped garden. CONTEXT The villa is located in the municipality of Spilamberto, a 30-minute drive from Bologna and 20 from Modena; convenient to the town''s amenities and accessible by public transportation. An ideal choice for those seeking an elegant residence that offers a pleasant outdoor space without sacrificing the convenience of proximity to the city center. THE HOUSE It currently comprises three separate apartments, each approximately 180 square meters in size, in good internal condition and ready to move into. Each apartment occupies an entire floor and is accessible via an internal staircase connecting the various levels. - Ground floor apartment: entrance via an external marble staircase, furnished entrance hall, large double-volume living room, eat-in kitchen, two double bedrooms, two bathrooms; additional access via external balconies and a shared staircase. - First floor apartment: hallway accessed from a shared staircase, eat-in kitchen, living room, 3 bedrooms, two bathrooms, and a small terrace. - Second floor apartment: hallway accessed from a shared staircase, eat-in kitchen, living room, two bedrooms, study, and bathroom. This apartment also offers access to the turret terrace, offering the possibility of creating a unique space, full of charm and light. - Basement: large rumpus room, study, laundry room, cellars and various rooms, technical room for the boiler room. PROPERTY CONDITIONS The interior conditions are very good, and all rooms in the three apartments are perfectly habitable. Slight differences in the interior layout and s', 'Spilamberto', 'Modena', 'emilia-romagna', 'via Vignolese', 44.5247259, 11.0198549, 'https://www.idealista.it/immobile/33883920/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/36/c3/3a/733794316.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/36/c3/3a/733794316.webp"]', 41, 'villa', 'villa', 64.0, 84.0, 40.0, 100.0, 56.0, 54.0, 62.0, 1053.0, 'Bologna (BLQ)', 21.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (86, '32826274', 198000.0, 192.0, 4, 2, 'Semi-detached house in via Geminiani Valente, 9', 'Semi-detached house FREE ON THREE SIDES WITH LARGE COURTYARD of 370sqm; it is spread over two floors plus a windowed attic of 25sqm (minimum H 1.80 max 3.00). The Ground Floor consists of comfortable services in spacious environments: tavern with fireplace and service kitchen for convivial gatherings, complete bathroom with window, very large laundry room that also lends itself as a games room or hobby room, double garage, storage room, boiler room and canopy. First Floor: entrance into the living area consisting of a very bright living room served by a kitchen that lends itself to all furnishing solutions; complete bathroom with bathtub, 3 bedrooms, one double, one twin and one single. IDEAL SOLUTION FOR PARENTS AND CHILDREN which allows you to host the two family units close but independent, both served by an external area organized partly in a paved courtyard, partly in a garden and partly in a vegetable garden with double automated driveway entrances. Roof recently renovated with sheath, solar panels and photovoltaics. Good energy efficiency thanks to the coat. Solution in excellent condition, because revisited in recent years. This OPPORTUNITY is located in a quiet area near the countryside, but also to the convenience of being able to reach the center of Fusignano in a few minutes. € 198,000. 00 OFF 1017.', 'Fusignano', 'Ravenna', 'emilia-romagna', 'via Geminiani Valente, 9', 44.4800738, 11.9832474, 'https://www.idealista.it/immobile/32826274/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/37/79/c8/696131338.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/37/79/c8/696131338.webp"]', 29, 'semidetachedHouse', 'house', 64.0, 86.0, 40.0, 80.0, 56.0, 46.0, 68.0, 1031.0, 'Bologna (BLQ)', 55.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (87, '34794887', 210000.0, 350.0, 12, 3, 'Detached house in via Bosino', 'Immersed in the rolling hills of the Monferrato region, this property welcomes you with a simple and genuine atmosphere. Located in Montegrosso d’Asti, in a small hamlet halfway between Agliano Terme and Costigliole d’Asti, this country house is ideal for accommodating two family units. Fully independent, it offers wide-ranging views of the surrounding vineyards, creating private corners where you can enjoy the tranquility and colors of the landscape at any time of day. The basement features a charming vaulted cellar. One part of the house, with a separate entrance, has been tastefully and recently renovated. On the ground floor, there is a spacious entrance hall; the first floor includes a fully equipped kitchen, hallway, bedroom, walk-in closet, and bathroom. The other part of the house, also with its own independent entrance, comprises a living room, fully equipped kitchen, storage room, and bathroom on the ground floor. The first floor features three bedrooms, a hallway, a bathroom, a utility room (which could be used as a fourth bedroom), and a balcony. Completing the property are a large storage room at the back of the house, a practical garage at the front, and conveniently located across from the house, a 2,200 m² plot of land.', 'Montegrosso d''Asti', 'Asti', 'piemonte', 'via Bosino', 44.7972005, 8.2267484, 'https://www.idealista.it/immobile/34794887/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/68/c6/3d/771876381.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/68/c6/3d/771876381.webp"]', 40, 'independantHouse', 'house', 64.0, 95.0, 15.0, 60.0, 72.0, 45.0, 70.0, 600.0, 'Torino (TRN)', 64.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (88, '33032285', 230000.0, 400.0, 12, 2, 'Detached house in frazione Cimaferle, 213', 'Early 20th Century Ancient Farmhouse for Sale – A Private Oasis in the Heart of Nature! In a private yet easily accessible setting, we offer for sale a historic farmhouse dating back to the early 1900s, perfect as both a private residence and a charming accommodation facility. The property comprises a main building divided into three dwellings: a spacious and characterful master residence, two secondary units ideal for conversion into guest accommodations or a B&B; a second independent building, connected to the main one by a characteristic portico, perfect for creating another accommodation unit or a creative atelier; and agricultural outbuildings that complete the structure, offering further potential for expansions or rural activities. All this is set within 53,000 m² of land, partly woodland and partly arable, ensuring absolute privacy and an authentic connection with nature. Strategic location: easily reachable, yet far from the chaos, ideal for those seeking tranquility without sacrificing convenience. A rare opportunity for those who wish to live or invest in a place rich in history, charm, and potential.', 'Ponzone', 'Alessandria', 'piemonte', 'frazione Cimaferle, 213', 44.5606981, 8.4830514, 'https://www.idealista.it/immobile/33032285/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2b/e4/54/702948924.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2b/e4/54/702948924.webp"]', 60, 'independantHouse', 'farmhouse', 64.0, 98.0, 15.0, 80.0, 54.0, 49.0, 72.0, 575.0, 'Genova (GOA)', 33.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (89, '33175073', 148000.0, 300.0, 12, 2, 'Casale/cascina in viale Marconi', 'Fully detached housing complex consisting of two adjacent residential units and some accessory buildings. The exposure of the buildings is excellent and in the green, thanks also to the property land that surrounds the entire complex. The two present dwellings overlook the large inner courtyard and enjoy excellent privacy.  The FIRST DWELLING is on two levels for a total of 150 sqm, in addition to the attic and the basement with charming cellar characterized by brick vaults. The ground floor houses the living area that consists of a living room, a bathroom and a kitchenette adjacent to the dining room with exposed wooden beams. On the second floor are two spacious bedrooms. This living unit is immediately usable. The SECOND DWELLING has two floors for a total of about 125 sqm, to which is added the attic floor. On the ground floor is the living area with kitchen, living room and bathroom. On the second floor there are three bedrooms. The second floor consists of the attic room, which retains the charm of the period thanks to the traditional terracotta tiles. The building is habitable, but with restoration work, the original features of the building could be emphasized. The property is completed by some ACCESSORY BUILDINGS, including two garages, a porch and the old stable with overhanging barn and woodshed, all of which overlook the courtyard. There is also an additional porch located at the rear. In the courtyard, close to the buildings, there are two ancient wells. The total land surface is about 6,000 square metres, and includes, in addition to the central courtyard, the surrounding land where there is another well with spring water used to irrigate the vegetable garden and fruit trees.', 'Bergamasco', 'Alessandria', 'piemonte', 'viale Marconi', 44.8237436, 8.4599772, 'https://www.idealista.it/immobile/33175073/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/aa/00/2b/739985377.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/aa/00/2b/739985377.webp"]', 63, 'casalicascine', 'casale', 64.0, 100.0, 15.0, 80.0, 54.0, 63.0, 61.0, 493.0, 'Genova (GOA)', 55.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (90, '34632149', 36750.0, 120.0, 6, 2, 'Semi-detached house in largo Armando Diaz, 11', 'Remax offers for sale in the characteristic village of Celenza Valfortore (FG), a detached house spread over two levels plus an attic, ideal as a primary residence or holiday home. The property is developed as follows: Ground floor: entrance into a room with kitchen, a small bathroom, and a small laundry area. To the left, there is a small living room, internally connected to the garage via a connecting door, ensuring practicality and comfort. Upper floor: sleeping area consisting of a double bedroom with a balcony, a second bedroom also with a balcony, a bathroom, and a small living room that disengages the rooms. Attic floor: accessory space usable as a storage room or closet. The property enjoys an independent entrance, good space distribution, and double exposure thanks to the balconies, which bring brightness to the rooms. An excellent opportunity for those seeking an independent house in a quiet setting, in the heart of the village. For further information or to arrange an appointment, do not hesitate to contact us. Don''t follow us on social media yet? Come and visit our Facebook and Instagram profiles to find lots of useful information about the real estate world!', 'Celenza Valfortore', 'Foggia', 'puglia', 'largo Armando Diaz, 11', 41.5614381, 14.9806539, 'https://www.idealista.it/immobile/34632149/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/16/e1/71/763139861.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/16/e1/71/763139861.webp"]', 31, 'semidetachedHouse', 'villa', 63.0, 100.0, 40.0, 60.0, 60.0, 48.0, 57.0, 306.0, 'Napoli (NAP)', 95.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (91, '34227068', 990000.0, 480.0, 6, 5, 'Casale/cascina in strada di Anqua no number', 'Radicondoli Tenuta di Anqua: Restored farmhouse with swimming pool I would start with the estate Anqua is formed by the village, an original plant of the 1500s of exceptional historical and architectural value, with an extension of about 1,000 hectares and with 13 farmhouses. The estate is among the oldest and largest in Tuscany. It has never been a tourist destination nor the seat of important and prestigious wineries such as Banfi, Antinori, Frescobaldi, etc., therefore less known, but to which it yields nothing, both for historical and architectural value and for landscape and naturalistic charm. Podere Giardino: the farmhouse and the garden Far from any view, it is one of the thirteen farmhouses of the estate, among the closest to the village, from which it is about 1 km away and is the best kept and easiest to access. Sheltered from the north, just below the village of Anqua, it is one of the most beautiful shapes of Tuscan vernacular architecture. Perfect and radical restoration; both in the structural part and in the finishes, with fixtures, doors and internal shutters in pastel blue: a small point of Provence, very widespread in Tuscany, which revives a little the excess of austerity of the national rural architecture and is especially appreciated by tourists. The two floors are not connected to each other, respecting the original layout, with an external staircase to access the upper floor; the most rational hypotheses are being studied for the construction of an internal staircase, which is not indispensable, given the amount of space available on each of the floors. The swimming pool is a few meters from the property, although closed to the eye with a hedge of very thick Pyracantha, which also surrounds the garden and so dense that it also prevents the passage of wild animals. Brief description of the property and interior spaces - The ground floor: entrance, dining room, kitchen, a very large living room and a smaller one, hallway, bathroom with tub, int', 'Radicondoli', 'Siena', 'toscana', 'strada di Anqua no number', 43.2186296, 10.9943764, 'https://www.idealista.it/immobile/34227068/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/9a/dc/0b/746244717.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/9a/dc/0b/746244717.webp"]', 76, 'casalicascine', 'casale', 63.0, 56.0, 40.0, 60.0, 64.0, 74.0, 72.0, 2062.0, 'Firenze (FLR)', 68.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (92, '34996156', 600000.0, 214.0, 5, 2, 'Semi-detached house in strada di Fogliano', 'Just ten minutes from the heart of Siena, along a scenic country road winding through the rolling Tuscan hills, you reach a refined, expertly renovated hamlet. Within this exclusive setting is this prestigious portion of a farmhouse, where the authentic charm of tradition meets the elegance of contemporary design. The recent renovation, meticulously detailed, has enhanced the original materials – stone, solid wood, authentic volumes – harmonizing them with modern finishes and highly distinctive architectural solutions, creating sophisticated and timeless environments. There are three access points to the property, designed to ensure comfort and privacy: direct access from the approximately 90 sqm garage, independent pedestrian access, and an exclusive gate leading to the six private parking spaces. From the moment you arrive, your gaze is lost among the iconic Crete Senesi hills and the Siena skyline silhouetted against the horizon. An extraordinary panorama that becomes an integral part of daily life, a silent protagonist of every view. The ground floor welcomes a magnificent open-plan living area, where the kitchen, conversation area with fireplace, and dining room interact in a spacious and bright environment, ideal for convivial moments and intimate atmospheres. A single bedroom and a bathroom complete this level. A designer staircase leads to the upper floor, where an elegant mezzanine with a double view – enhanced by imposing solid wood beams – offers a striking glimpse towards Siena. This space, with its strong scenic impact, can easily become an additional double suite. The sleeping area continues with a single bedroom, a refined master bedroom, and a large bathroom with a window and bathtub, designed as an area dedicated to well-being and relaxation. Outside, the fenced garden and private olive grove frame the property in a setting of absolute tranquility and privacy, offering the privilege of living immersed in the Tuscan countryside without sacrificing pr', 'Siena', 'Siena', 'toscana', 'strada di Fogliano', 43.2624722, 11.3064496, 'https://www.idealista.it/immobile/34996156/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/54/d7/9c/776932500.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/54/d7/9c/776932500.webp"]', 25, 'semidetachedHouse', 'farmhouse', 63.0, 23.0, 40.0, 60.0, 93.0, 69.0, 79.0, 2804.0, 'Firenze (FLR)', 61.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (93, '31378620', 629000.0, 390.0, 8, 5, 'Villa in viale Alcide de Gasperi, 2', '**Splendid Independent Villa for Sale** Discover this magnificent villa, free on four sides, completely renovated with high-quality materials, located in a privileged position. The property is spread over four floors, offering ample space and modern comforts. On the ground floor, a welcoming hallway leads to a double living room, a kitchen, a bathroom and a double bedroom. The first floor houses four double bedrooms, two bathrooms and a habitable terrace. On the second floor, a furnished attic opens onto a terrace with panoramic views of the surrounding valley. The basement offers cellar rooms, double services, a technical room, two storage rooms and a garage. Surrounded by a private garden and a patio equipped as a living area, the villa has two entrances, an alarm system, awnings, air conditioning, a dumbwaiter and a private well for irrigation. With 390 m² of commercial space and 306 m² of usable space, this villa offers eight habitable rooms, five bathrooms, accessory rooms, and a surrounding garden of 500 m². Free and available immediately, this villa represents a unique opportunity for those seeking elegance and functionality. TAKE A FIRST REMOTE VISIT WITH THE 3D VIRTUAL TOUR NOW: you can move inside the property to get a first approach immediately. For further information and to arrange a visit, you can contact us from 9:30 am to 1:00 pm and from 3:00 pm to 7:00 pm from Monday to Friday, or by sending a request to the "CONTACTS" section. All the details and technical data indicated in the published descriptions have been provided in good faith following an on-site inspection and based on the available documentation. We assume no responsibility for any inaccuracies. Please note that, to protect the privacy of the owners, the point indicated on the map is purely indicative.', 'Castelfranco Piandiscò', 'Arezzo', 'toscana', 'viale Alcide de Gasperi, 2', 43.6436121, 11.5461052, 'https://www.idealista.it/immobile/31378620/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b7/fd/d4/653691536.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/b7/fd/d4/653691536.webp"]', 34, 'villa', 'villa', 63.0, 77.0, 40.0, 80.0, 64.0, 54.0, 61.0, 1613.0, 'Firenze (FLR)', 33.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (94, '35049089', 750000.0, 340.0, 15, 3, 'Villa in via del Campisano', '"The Lemon Farmhouse"  Stunning Tuscan villa with sea views and a panoramic garden" Corsanico  Ref. REA514      Nestled in the quiet hills of Versilia, among olive trees, sunshine, and lemon groves, the green valley gently sloping toward the blue sea. A picture from every window, this property unfolds before us like the lines of a poem, for those who know how to experience the space, the atmosphere, and the view.      In the characteristic village of Corsanico, LEONARDO REAL ESTATE exclusively offers this splendid, completely renovated rustic villa. It represents an ideal solution for those who wish to live in a panoramic setting, surrounded by greenery and with a splendid view of the Versilia sea.  The property, approximately 340 square meters, stands out for its perfect balance of Tuscan charm and contemporary comfort: exposed beams, welcoming spaces, and spacious, bright spaces that open to the outdoors, where a large terraced garden allows you to fully enjoy the natural surroundings and the picturesque sea views. The excellent exposure ensures natural light throughout the day, making every room particularly pleasant to live in.  A panoramic infinity pool can be easily created.  The house is designed to offer great versatility, thanks to a distribution of spaces that makes it perfect both as a large family residence and as a solution for two families.      The main room of the house is on the lowest floor, at the height of the garden and with a view surrounded by splendid lemon trees.  A spacious tavern with a fireplace, featuring a large living and dining area with kitchen, large fireplace and a bathroom.  Thanks to the natural terracing of the land, this floor enjoys direct access to the garden, becoming an ideal space for convivial moments, dinners with friends, or relaxation in the milder seasons.      On the raised ground floor, accessible directly from the outside and also internally from the tavern via an internal staircase, there is a first complete apart', 'Massarosa', 'Lucca', 'toscana', 'via del Campisano', 43.9086694, 10.3013789, 'https://www.idealista.it/immobile/35049089/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/12/f8/36/778676900.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/12/f8/36/778676900.webp"]', 45, 'villa', 'farmhouse', 63.0, 50.0, 40.0, 100.0, 64.0, 70.0, 69.0, 2206.0, 'Pisa (PSA)', 26.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (95, '34948978', 417000.0, 204.0, 6, 3, 'Detached house in Soiana', 'Detached House with Exclusive panoramic Garden Are you looking for an elegant but sustainable environment? Don’t miss this opportunity! Discover Soiana, a beautiful location in Tuscany in the Municipality of Terricciola. This single house, with its 180 square metres of unparallelled charm, offers a perfect balance between privacy and comfort. Underfloor heating give the house a warm and cosy atmosphere.  Property Details: Composition: Kitchen, Living Room, 3 Bedrooms, Triple Bathrooms, Tavern, Terraces Exclusive Garden: Surrounds the house, panels shield making it a private refuge. Impeccable condition: Energy class C for those looking for luxury and sustainability. Built in 2018: Use of high quality materials and energy efficiency measures. Customisation possibilities: Initially designed for two families, the house can be easily divided into two apartments, maintaining the possibility of communication or independence. A Dream that Becomes Reality: Imagine waking up every morning in your room with breathtaking views of the Tuscan hills and a large balcony at your disposal. This villa offers a unique fusion of tradition and modernity, with exposed beams, wood-burning fireplace, combined with modern comforts such as home automation and underfloor heating, marble and terracotta kitchen work surfaces and your own built in pizza oven.  Ideal Position: Don''t miss the extraordinary opportunity to live in an enviable position, for only 417,000 Euros. Contact us today to schedule a visit and discover every detail of this magnificent villa. Note: The address indicated only identifies the area of the property, respecting the privacy of the sellers. Distance: Casciana Terme Spa: 6 km Ponsacco: 7 km FI-PI-LI highway: 12 km Pontedera (train station): 14 km Pisa - Galileo Galilei International Airport: 32 km Cala dei Medici - harbour: 36 km Sea Castiglioncello: 37 km Livorno: 40 km Lucca: 43 km Versilia: 70 km Florence: 75 km Don''t miss this unique opportunity!', 'Terricciola', 'Pisa', 'toscana', 'Soiana', 43.5533995, 10.6466072, 'https://www.idealista.it/immobile/34948978/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a6/db/ce/775267060.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/a6/db/ce/775267060.webp"]', 40, 'independantHouse', 'villa', 63.0, 57.0, 40.0, 100.0, 64.0, 61.0, 68.0, 2044.0, 'Pisa (PSA)', 25.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (96, '33926847', 1370000.0, 590.0, 15, 7, 'Villa in via di Lucente, 2', 'In the heart of Tuscany, among the rolling hills of Pelago, stands "Villa Lucente": a residence that has guarded stories, voices, and gazes for centuries. Every stone, every beam, every glimpse tells of different eras, intertwined in a harmony that can still be felt today. Its roots sink into the 1700s, but its soul is older: an ideal bridge between the Renaissance and the Middle Ages. Born as a farm, then a village house, then a family residence, Villa Lucente has been the heart of community life, a place of meeting and memory. A connection with art According to sources from the Municipality of Pelago, Lorenzo Ghiberti, the famous artist of the Florentine Renaissance, may have been born right here. A detail that adds charm and uniqueness to this villa which, more than a building, is a fragment of living history. A garden that embraces the house Outside, a lush garden with centuries-old plants and two majestic cedars from 1931 frames the property. A place where nature and architecture merge in a rare, almost poetic balance. The Villa The double entrance makes the property ideal for multiple families, thanks to the presence of several independent units. Ground floor: Main entrance Eat-in kitchen Double living room with original terracotta floors and exposed beams Study with period fireplace Bathroom with window Laundry Outdoor kitchen, perfect for enjoying the summer and dinners in the garden First floor: Bright central living room Four double bedrooms Two bathrooms with windows Panoramic terrace with views of the Tuscan hills Spaces to live in Beyond the garden, a splendid swimming pool offers moments of relaxation and silence. Not far away, an old barn testifies to the rural past and offers possibilities for recovery and personalization. The surrounding land, enriched by olive trees and Mediterranean plants, completes an authentic and harmonious picture. Two independent one-bedroom apartments, currently rented, guarantee an excellent income and maintain the privacy', 'Pelago', 'Firenze', 'toscana', 'via di Lucente, 2', 43.7696158, 11.4635145, 'https://www.idealista.it/immobile/33926847/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/06/01/b1/735272690.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/06/01/b1/735272690.webp"]', 123, 'villa', 'villa', 63.0, 44.0, 40.0, 100.0, 64.0, 80.0, 66.0, 2322.0, 'Firenze (FLR)', 21.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (97, '35120247', 27000.0, 80.0, 4, 1, 'Estate', 'In the authentic heart of western Sardinia, in the quiet and charming village of Bauladu, we offer for sale an ancient property rich in history and charm. A corner of Sardinia where time slows down, between tradition, nature, and the sea. Bauladu is a small village nestled among hills and Mediterranean countryside, a few minutes from Oristano and strategically located between the sea and the hinterland, close to the SS131, the main regional artery that conveniently connects the island''s ports and airports. An optimal position that allows you to live the tranquility of an authentic village while remaining well connected to the entire territory. From here, you can easily reach some of the most suggestive locations on the coast: the crystalline beaches of the Sinis Peninsula, with white quartz and turquoise waters, and the spectacular natural cliff of S’Archittu, famous for its rock arch sculpted by the sea. The house retains the character of old homes: walls that tell stories, authentic spaces, and the timeless charm of traditional Sardinian architecture. A perfect place for those who dream of restoring and giving new life to an ancient dwelling, transforming it into a unique residence or a peaceful retreat a short distance from the sea. A total renovation project was approved for the property, which expired a few months ago, but has already initiated important structural interventions. The work has indeed begun and includes: • Remaking of the subfloor with an aeration system and preparation of plumbing and air conditioning systems; • Consolidation and reinforcement of existing walls; • Preparation of wooden beams for the construction of the roof. Also included in the price are some materials already prepared for the completion of the works: • Reed mats for the roof covering, carefully stored away from the weather; • New basalt doorframes and window frames for the perimeter, in perfect harmony with the local traditional architecture. The property therefore represents ', 'Bauladu', 'Oristano', 'sardegna', 'Bauladu', 40.021442, 8.6703141, 'https://www.idealista.it/immobile/35120247/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/48/db/cf/780867577.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/48/db/cf/780867577.webp"]', 19, 'countryHouse', 'villa', 63.0, 100.0, 40.0, 60.0, 56.0, 51.0, 59.0, 338.0, 'Cagliari (CAG)', 92.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (98, '35034841', 75000.0, 140.0, 6, 2, 'Villa in via Roberto dall''Oca, 26', 'Buying opportunity! Detached villa on the ground and first floors with a large fenced and landscaped outdoor area, recently renovated, in a private location yet close to the town center. The property comprises: GROUND FLOOR: Large fenced and landscaped garden with pedestrian and driveway entrances with remote control, ample parking, entrance with security door, living room, kitchen, laundry room with dryer, and heating system with both a natural gas boiler and a wood-burning stove, corn, and other fuels, double bedroom, and bathroom. FIRST FLOOR: Two double bedrooms, one with a master bathroom. The villa is equipped with radiator heating, heat pump air conditioning, double-glazed wooden window frames, and is furnished. Energy efficiency rating currently being determined. Follow us on social media to stay up to date on news, local events, and real estate opportunities. We''re on Facebook at: Need help organizing trips, visits, or food and wine tours in the Comacchio area? No problem, choose the date and follow the link below. With just a few clicks, you''ll have an endless choice of possible experiences and tastes.', 'Mesola', 'Ferrara', 'emilia-romagna', 'via Roberto dall''Oca, 26', 44.908507, 12.181565, 'https://www.idealista.it/immobile/35034841/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/0c/d0/c8/778280275.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/0c/d0/c8/778280275.webp"]', 25, 'villa', 'villa', 63.0, 100.0, 40.0, 60.0, 56.0, 50.0, 58.0, 536.0, 'Bologna (BLQ)', 82.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (99, '34865895', 69000.0, 120.0, 3, 1, 'Casale/cascina in Borgata Brondo, 3 -18', 'Your retreat in Langa: rustic with land There are houses born to be lived in every day. And then there are places you choose to return to and breathe. In Mombarcaro, at the highest point of Alta Langa, in a dominant and panoramic position, we offer a rustic property surrounded by 118,000 sqm of land: a corner of the world where silence has a sound and the panorama becomes part of everyday life. Here you don''t hear traffic. You don''t feel rushed. You only hear the wind in the trees and the slow rhythm of the seasons. The rustic stone house preserves the authentic soul of old farmhouses. It is completely to be renovated, yes. But this is precisely its value: it can become what you desire. A second home to retreat to on weekends. A place to spend the summer with family. A buen retiro where you can invite friends, light the fireplace, and watch the hills change color at sunset. The position is dominant, the view is open over the valleys of Alta Langa, with a feeling of freedom difficult to explain until you experience it. The 118,000 sqm of land surrounding the property are not just a number. They are space. They are privacy. They are possibilities. Woods, hills, unspoiled nature: an ideal setting for those who desire a second home away from the city, yet easily accessible. It can be your refuge. It can become a life project. It can simply be the place to switch off everything and find yourself. Mombarcaro is a still genuine territory, with wide panoramas, clean air, and a slow rhythm that regenerates. It is not a ready-made house. It is a dream to build. If you are looking for a true second home, far from the chaos, immersed in one of the most fascinating landscapes of Piedmont, this property is worth seeing. Contact us for more information and to discover if this can become your refuge in Langa.', 'Mombarcaro', 'Cuneo', 'piemonte', 'Borgata Brondo, 3 -18', 44.4820342, 8.0993828, 'https://www.idealista.it/immobile/34865895/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/36/bf/e1/772056545.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/36/bf/e1/772056545.webp"]', 26, 'casalicascine', 'casale', 63.0, 98.0, 15.0, 80.0, 54.0, 61.0, 61.0, 575.0, 'Genova (GOA)', 59.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (100, '34017684', 59000.0, 140.0, 5, NULL, 'Terraced house in via Vittorio Alfieri, 18', 'In one of the most charming villages of the Langhe, a portion of a stone farmhouse to be renovated, located in the historic center of Castiglione Falletto, in the heart of the renowned Barolo cru. The property is spread over two levels and offers ample possibilities for customization: each room can be shaped according to one''s needs, while maintaining the charm of traditional Langhe architecture. An ideal solution for those who wish to create a tailor-made home that is a private residence, a holiday home, or an investment in quality tourism immersed in the magic and scents of the UNESCO World Heritage hills. A project to imagine, a dream to realize in the heart of the Langhe. The Dotta real estate agency has stood out for years in the local landscape thanks to the extreme seriousness and competence of its staff. It is part of our mission to accompany the client in the process of evaluating and choosing the property that best suits their expectations and needs. Contact us now to view this house in the Langhe together. We will be happy to accompany you to the property without any obligation, with courtesy and professionalism.', 'Castiglione Falletto', 'Cuneo', 'piemonte', 'via Vittorio Alfieri, 18', 44.6226932, 7.9765992, 'https://www.idealista.it/immobile/34017684/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/dc/8b/03/738439579.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/dc/8b/03/738439579.webp"]', 11, 'terracedHouse', 'farmhouse', 63.0, 100.0, 15.0, 60.0, 72.0, 58.0, 53.0, 421.0, 'Torino (TRN)', 69.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (101, '33726188', 114000.0, 325.0, 12, 1, 'Casale/cascina in Regione Sconi', 'Country House to be Renovated, Independent and at the Top of the Hill! A traditional pietra di Langa property, located within the cultural landscape of the Langhe-Roero and Monferrato area, recognized by UNESCO as a World Heritage Site since 2014. Just 1.5 km from the center of Cassinasco and 5 km from the renowned town of Canelli. The house is surrounded by sandy hills where, thanks to the fresh climate, white wine grapes are predominantly cultivated. The property enjoys a remarkable panoramic view. The farmhouse, in need of renovation, measures approximately 325 sqm and may also be suitable for use as a two-family residence, hospitality structure, and/or bed and breakfast. Independent on four sides, it comes with a courtyard of 1,460 sqm. In addition, the property includes another 4,760 sqm of land. Basement: storage room and cellar. Ground floor: kitchen, living room, 3 storage rooms, laundry, bathroom, warehouse, henhouse, portico, and storage area. First floor: 2 bedrooms, storage room, former hayloft with exposed roof, and 2 balconies.', 'Cassinasco', 'Asti', 'piemonte', 'Regione Sconi', 44.6869423, 8.3129983, 'https://www.idealista.it/immobile/33726188/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ae/26/5f/728223028.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ae/26/5f/728223028.webp"]', 100, 'casalicascine', 'casale', 63.0, 100.0, 15.0, 80.0, 54.0, 58.0, 62.0, 351.0, 'Genova (GOA)', 52.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (102, '33326758', 475000.0, 620.0, 10, 3, 'Villa in via Roma', 'A haven on the hilltop with breathtaking views over the Monferrato! Perched in a commanding position, with a spectacular panorama that stretches across the entire Val Tiglione, this is truly a unique home for those seeking light, space, and silence. This recently built villa, measuring 311 sqm, offers modern comforts and timeless beauty in equal measure. The property sits on a plot of land of 13,357 sqm (including the lot), perfect for future projects—such as adding a swimming pool, a small orchard, or simply enjoying nature. The driveway leads to a spacious basement, cleverly designed to include a large garage/storage area totaling 309 sqm, a wine cellar, an office/study, the boiler room, and a laundry with bathroom. An internal staircase connects to the main living area, featuring a bright open-plan kitchen (included in the price) and dining area that opens directly onto the garden—ideal for enjoying country life both indoors and outdoors. This floor also offers a spacious living room, a bathroom/laundry room, and a bedroom; this level provides ample space for family and guests. Upstairs, with stunning views in every direction, you’ll find two bedrooms, a hallway, a bathroom, and another bedroom with a walk-in closet and en-suite bathroom. Other highlights: * Natural light all year round * Video surveillance system * External wall insulation * Detached on all four sides * Insulated roof * Alarm system * Underfloor heating * Central vacuum system Ready to fall in love at first sight? Book your visit today.', 'Vigliano d''Asti', 'Asti', 'piemonte', 'via Roma', 44.8329433, 8.2326145, 'https://www.idealista.it/immobile/33326758/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/3d/50/e2/773795083.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/3d/50/e2/773795083.webp"]', 113, 'villa', 'villa', 63.0, 80.0, 15.0, 60.0, 72.0, 59.0, 67.0, 766.0, 'Torino (TRN)', 61.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (103, '34341729', 3000000.0, 2700.0, 50, 27, 'Masseria in contrada pallone, 1', 'Wrapped in the ancestral silence of the Apulian countryside, this eighteenth-century masseria reveals itself as one of the most fascinating examples of fortified rural architecture. A timeless property that holds over 2700 sqm of interior spaces and extends across a private estate of about 19 hectares, cultivated with arable land and enriched by a vast ancient olive grove that celebrates the agricultural tradition of the territory. A majestic arched entrance leads to the large central courtyard, dominated by the main residence, compact and noble in its square, defense-inspired form. Around it, trulli and ancient agricultural structures recount centuries of rural life, while the presence of stone bridges and old wells testifies to the constructive ingenuity and efficiency of the original settlement. The roots of the masseria date back to a period prior to 1727; over the centuries, the property was the scene of episodes linked to post-unification brigandage, chapters that enhance its historical and cultural value. The interiors preserve the architectural authenticity of the residence: large cross vaults define the rooms of the main building, while the splendid reception hall welcomes guests beneath extraordinary exposed star vaults. Here, a majestic stone fireplace becomes the scenic heart of the residence. In addition to the event hall, the property features trulli and large spaces dedicated to guest accommodation, perfectly integrated into the complex and ideal for refined hospitality. The masseria is already prepared to be managed as a high-level hospitality structure, thanks to dedicated reception areas and professional services designed for guest comfort. Designed for top-tier hospitality use, the property offers large industrial kitchens, an internal laundry, an equipped pantry, and service areas that ensure impeccable operations. An additional value is the semi-basement level, an evocative space dedicated to wellness and personal care, ideal for creating an exc', 'Francavilla Fontana', 'Brindisi', 'puglia', 'contrada pallone, 1', 40.5817872, 17.6155041, 'https://www.idealista.it/immobile/34341729/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/6f/4f/a9/752392643.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/6f/4f/a9/752392643.webp"]', 74, 'masseria', 'masseria', 62.0, 57.0, 40.0, 60.0, 60.0, 76.0, 71.0, 1111.0, 'Bari (BRI)', 95.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (104, '28121179', 209000.0, 100.0, 5, 1, 'Trullo in contrada Falghero no number', 'Trulli and lamie complex for sale in the countryside of Ostuni, Puglia TRULLO PARADISO PUGLIESEKEY DETAILS -Trulli and lamie complex -Four-cone trullo -Approximately 7 km from the centre of Ostuni, in the Falghero district -Internal surface area of approximately 100 m² -Land of approximately 5,000 m² Trullo Paradiso Pugliese exudes an intimate atmosphere that will make it your true home away from home. You can spend your time outdoors, relaxing to the rustling of the olive groves, or on the sofa in your new cosy living room... the choice is yours! Nestled among the majestic olive trees of typical Apulian landscapes, at Trullo Paradiso Pugliese, the green of the thousand-year-old olive trees, twisted like souls in torment, the reddish earth cut by dry stone walls and the whiteness of the trulli are the real protagonists. DETAILED DESCRIPTION OF THE TRULLO INTERIORS: the property consists of a lamia with a kitchen and fireplace, a double bedroom and a bathroom. Between the main house and the trullo, there is an old cellar that would be ideal for converting into a spa.The four-cone trullo has an alcove on the right side and a double alcove on the left side of the central cone. Adjacent to the trullo is a garage measuring approximately 4x5m. THE EXTERIORS: the entire complex occupies a location where you can live in complete privacy but surrounded by numerous luxury facilities. The land, which is completely fenced and flat, covers an area of approximately 5,000 square metres. On this wonderful expanse of red earth, you can admire around 50 olive trees, fruit trees and a characteristic vineyard. UTILITIES AND SERVICES The property is in need of renovation. N.B. The price of €209,000 refers only to the structure with approximately 5,000 square metres of land. There is the possibility of purchasing separately approximately one hectare of land with approximately 450 olive trees at a price of €80,000, on which it would be possible to build a villa of approximately 100 square', 'Ostuni', 'Brindisi', 'puglia', 'contrada Falghero no number', 40.6637061, 17.6107594, 'https://www.idealista.it/immobile/28121179/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/69/0c/ae/539778698.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/69/0c/ae/539778698.webp"]', 97, 'trullo', 'trullo', 62.0, 0.0, 40.0, 60.0, 92.0, 70.0, 96.0, 2090.0, 'Bari (BRI)', 89.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (105, '34676138', 1200000.0, 436.0, 8, 4, 'Villa in strada Provinciale 23 delle Ville di Corsano', '**Villa for Sale South of Siena - A Paradise in the Tuscan Countryside** Discover this splendid villa located just 4 km from the historic center of Siena, nestled in the marvelous Tuscan countryside. Privacy and discretion are guaranteed, thanks to the strategic position of the property, which offers a panoramic view of the city and the surrounding hills. The single-family villa, built in 1978, is spread over three floors for a total of 400 sqm, with an accessory volume of 40 sqm used as a warehouse. The fenced garden of 8,500 sqm is a true corner of paradise, consisting of 5,200 sqm of exclusive courtyard and 3,300 sqm of agricultural land. The main building is set back from the road, ensuring tranquility and isolation. A private driveway leads to the entrance, where there is a welcoming open-plan kitchen, a dining-living room, two double bedrooms, and two bathrooms on the ground floor. On the first floor, a double bedroom with two accessory rooms and a small living room complete the offering. The basement is a true gem: a large living room with a fireplace, a service kitchen, a bar area, a study, and a cellar offer versatile spaces for every need. A renovation project for interiors and exteriors is included, with the possibility of creating a swimming pool and a photovoltaic system. The landscape permit for the accessory building has already been obtained, while that for the main building and external transformations is expected in spring 2026. Don''t miss the opportunity to live in this splendid corner of Tuscany!', 'Siena', 'Siena', 'toscana', 'strada Provinciale 23 delle Ville di Corsano', 43.2938495, 11.3177668, 'https://www.idealista.it/immobile/34676138/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/45/08/09/764933525.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/45/08/09/764933525.webp"]', 89, 'villa', 'villa', 62.0, 25.0, 40.0, 80.0, 93.0, 61.0, 74.0, 2752.0, 'Firenze (FLR)', 58.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (106, '34117289', 350000.0, 172.0, 5, 2, 'Villa in località Meliciano', 'On the top of a hill that offers glimpses of unspoiled nature and from which you can see the city of Arezzo in the distance, we are selling an independent stone villa that is reached after a kilometer of dirt road. The property, which is located in the middle of a small group of houses consisting of three units, was completely renovated in 2017 in keeping with the Tuscan style and is spread over two levels. On the ground floor there is a large living room with a splendid cortain suspended fireplace, a large kitchen with a dining area and a bathroom with a shower. On the first floor, which is accessed by a modern and original metal staircase, there are three double bedrooms and a large bathroom with a shower. In the sleeping area there is provision for installing hot/cold heat pumps. Outside there is an outbuilding of 15sqm used as a boiler room and laundry. The heating system is with a pellet boiler combined with a 500lt domestic hot water storage tank. The property includes a private garden with a beautiful centuries-old oak tree, an area for exclusive parking and a small olive grove. There is a well. If you are looking for a space surrounded by nature but close to all amenities where you wake up in the morning with the sounds and colors of nature, this is the ideal space for you.', 'Arezzo', 'Arezzo', 'toscana', 'località Meliciano', 43.5250048, 11.7887074, 'https://www.idealista.it/immobile/34117289/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/6c/1e/cf/767563408.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/6c/1e/cf/767563408.webp"]', 20, 'villa', 'villa', 62.0, 58.0, 40.0, 80.0, 64.0, 55.0, 71.0, 2035.0, 'Firenze (FLR)', 57.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (107, '28649067', 1180000.0, 220.0, 6, 3, 'Detached house in via Accursio no number', 'In a quiet street near Poggio Imperiale, a delightful early 20th-century villa in excellent condition. The property is arranged on two main levels plus a cellar in the basement. A large entrance leads us to a double living room with a fireplace, a dining room, and a comfortable kitchen. A single bedroom with a bathroom completes the raised ground floor. A beautiful pietra serena staircase leads us to a mezzanine with a storage room and a bathroom. Upstairs, there are 2 large double bedrooms with bathrooms and a terrace overlooking the private garden. The views are of the beautiful exclusive garden where there is a dependency of about twenty square meters, which the owners have used as a laundry and ironing room. The enclosed and intimate garden is lovely. The property also has a cellar. If desired, it is possible to purchase a parking space separately.', 'Firenze', 'Firenze', 'toscana', 'via Accursio no number', 43.7480875, 11.2378839, 'https://www.idealista.it/immobile/28649067/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ee/bb/ed/560652055.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/ee/bb/ed/560652055.webp"]', 43, 'independantHouse', 'villa', 62.0, 0.0, 40.0, 100.0, 95.0, 61.0, 83.0, 5364.0, 'Firenze (FLR)', 7.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (108, '32286224', 395000.0, 272.0, 12, 4, 'Villa in via Fratelli Manai', '**Enchanting Villa in Sindia: A Charming Retreat in Sardinian Tradition** Old village with character at approximately 20 minutes to the beach and to Bosa and at just 10 minutes to the SS 131 the major arterial route in Sardinia; the village is renowned for the hospitality of its inhabitants, for the numerous typically traditional fairs, festivals and horse riding along the main street of the town, for its numerous archaeological sites of national interest and for the extraordinary beauty of its uncontaminated nature with its verdant holm oaks, holly and cork trees in a place of silent perfection. In this context of simple but pleasantly stimulating life, we offer for sale a completely independent villa in excellent condition, finished with high-quality materials, with a large garden, enriched by a verdant planting of typically Mediterranean shrubs, such as red myrtle and holm oak. The house is on two levels, with driveway and several internal parking spaces, enriched by a splendid porch entirely covered with typical Sardinian stone. The First Floor has a wonderful partly covered veranda that surrounds the whole house, hall, large and luminous living room with fireplace, dining room, lounge area, bathroom, kitchen, hallway, second bathroom, three bedrooms, one with en-suite and private veranda and one with access to the private terrace; the Ground Floor is ideal for convivial moments thanks to the welcoming hospitality of the spacious rustic kitchen with fireplace, as well as a bathroom, cellar, large garage with tool storage. Built around 1990 and completed in the following years, it is equipped with central heating and air conditioning. This property is perfect for those looking for a comfortable and charming home in a historical context where the uncontaminated beauty of nature blends with the charm of Sardinian history and culture, a perfect combination of tranquility and comfort. Thanks to its low-traffic location and its Mediterranean garden, the villa is an oa', 'Sindia', 'Nuoro', 'sardegna', 'via Fratelli Manai', 40.2931749, 8.6557897, 'https://www.idealista.it/immobile/32286224/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e7/99/36/679429358.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e7/99/36/679429358.webp"]', 103, 'villa', 'villa', 62.0, 69.0, 40.0, 60.0, 56.0, 62.0, 74.0, 1452.0, 'Olbia (OLB)', 99.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (109, '33437895', 180000.0, 155.0, 4, 3, 'Terraced house in via Costantino Nivola, 1', 'BOSA: in the charming village, on Via Nivola, we offer for sale a recently built independent villa. The house is spread over three levels, offering ample space and modern comforts. Each floor has a bathroom, ensuring practicality and functionality for the whole family or for guests. Through the large and scenic entrance with stone columns, we access the ground floor, where we find the living room with an open-plan kitchen and the staircase connecting the three rooms; on the first floor, the three bedrooms offer sufficient space for a large family or for those who wish to start a hospitality business; there is also a large room of approximately 56 sqm ideal as a tavern, hobby room, study, or gym, directly connected to the garage. The private courtyard, accessible from the ground floor, represents a corner of tranquility, ideal for moments of outdoor relaxation; the location, set back from the road, guarantees further privacy. The recent construction ensures modern living standards, excellent materials, and high-quality finishes. This solution is perfect both as a first home and as an investment for hospitality activities, thanks to its strategic position and unique features.', 'Bosa', 'Oristano', 'sardegna', 'via Costantino Nivola, 1', 40.3029961, 8.4869792, 'https://www.idealista.it/immobile/33437895/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e4/d1/a8/717550831.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/e4/d1/a8/717550831.webp"]', 23, 'terracedHouse', 'villa', 62.0, 85.0, 40.0, 40.0, 56.0, 56.0, 71.0, 1161.0, 'Olbia (OLB)', 109.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (110, '31812206', 185000.0, 262.0, 13, 1, 'Casale/cascina', 'In a lovely, tranquil and very private position, halfway between Mango and San Donato, you find this property almost hidden away when you drive up the charming and romantic paved driveway. The old classical stone cascina is in need in renovation, but the roof is new, so the structure is still good, here you could realize further habitation rooms for a B&B or apartments. The current habitation is from the 70-ties, has doubleglazed windows and central heating on gas, the roof is new. Here we find three bedrooms, bathroom and kitchen/livingroom with amazing views over the valley with rolling vineyards toward Mango! The window in the living room is a live picture changing with the seasons! Underneath at full cellar with a bathroom and storagespace, to the side, between the building, the garage and further storage space. A third building completes the property which is surrounded by it’s own land of 8.675 sqm. Enormous potential in a fantastic contest and position!', 'Mango', 'Cuneo', 'piemonte', 'Mango', 44.6593333, 8.1552718, 'https://www.idealista.it/immobile/31812206/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/5d/67/f8/664433290.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/5d/67/f8/664433290.webp"]', 97, 'casalicascine', 'casale', 62.0, 86.0, 15.0, 60.0, 54.0, 59.0, 76.0, 706.0, 'Genova (GOA)', 61.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (111, '30273184', 275000.0, 676.0, 10, 2, 'Detached house', 'An independent building of app. 676 sqm, over three levels, in the charming and renowned village in the heart of the Langhe, in the midst of Barbaresco and just a few kilometres from Neive.  The property is suitable for receptive use (holiday home, B&B) and/or residential use, given its breathtaking panoramic position and generous dimensions. Land of about 3,259 sqm completes the property.', 'Neviglie', 'Cuneo', 'piemonte', 'Neviglie', 44.6899721, 8.1153258, 'https://www.idealista.it/immobile/30273184/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/5a/37/f6/617903439.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/5a/37/f6/617903439.webp"]', 73, 'independantHouse', 'villa', 62.0, 100.0, 15.0, 60.0, 54.0, 47.0, 72.0, 407.0, 'Genova (GOA)', 65.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (112, '34630817', 260000.0, 248.0, 8, 2, 'Detached house in via On. Giovanni Sodano', 'In the heart of the province of Asti, this historic residence offers a haven of peace and exceptional privacy, set within an expansive and well-kept garden/land that opens onto the panoramic landscapes of the Monferrato. The refined balance between the authenticity of a period property and the high standards of finishes that can be achieved will create an atmosphere of great charm—ideal for fully embracing Piemonte’s culture and traditions while maintaining a precious connection with the surrounding nature. Set in a secluded and commanding position over the gentle hills of Piemonte, this historic residence, in need of renovation, welcomes you with a large and carefully maintained garden/land of over 8,330 sqm. The property is an early-1900s farmhouse arranged over three floors, with an approximate commercial surface area of 250 sqm. It combines original architectural features with the potential to introduce modern comforts, ensuring in the future a high level of finishes and excellent energy efficiency. Access is via a private, tree-lined driveway that leads to the independent entrance, immersed in the privacy of a highly secluded setting. The plot opens onto a vast outdoor space with generous green areas, arable land, and a well-kept private garden—ideal for enjoying the surrounding tranquility and panoramic views over the vineyard-dotted hills. The exposed brick façade preserves the historic character of the building, while vaulted ceilings blend harmoniously with the internal brick vaults. Upon entering the ground floor, the space opens onto a hallway: to the right is a large living room, while to the left there is a spacious kitchen, an open portico, and a storage room. The three bedrooms are located on the first floor, along with two bathrooms, a hallway, and a balcony. Of particular note is the extensive structure, suitable for a variety of uses, as well as the potential for tourist accommodation thanks to its strategic position between the Monferrato and majo', 'Isola d''Asti', 'Asti', 'piemonte', 'via On. Giovanni Sodano', 44.8257267, 8.1835581, 'https://www.idealista.it/immobile/34630817/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7e/7b/b2/773779924.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/7e/7b/b2/773779924.webp"]', 61, 'independantHouse', 'farmhouse', 62.0, 55.0, 15.0, 80.0, 72.0, 63.0, 76.0, 1048.0, 'Torino (TRN)', 59.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (113, '32569159', 490000.0, 500.0, 12, 6, 'Semi-detached house in strada Comunale Santa Margherita', 'In the splendid Turin hills, a few kilometers from the center of Turin, we offer for sale two villas with approved PROJECT and related charges paid of approximately 150 square meters and 350 square meters with private garden. Possibility of starting work immediately, the renovation of the villa will be paid by the buyer. The 150 m2 villa will consist of an entrance onto a large living room with open kitchen, two bedrooms, one of which is double, and two bathrooms. The 350 m2 villa, on two levels, will consist of an entrance onto a large living room with open kitchen, five bedrooms, one double, three singles and a study, four bathrooms plus a laundry room. Large private garden and covered parking spaces.', 'Torino', 'Torino', 'piemonte', 'strada Comunale Santa Margherita', 45.0572424, 7.7105815, 'https://www.idealista.it/immobile/32569159/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2b/65/a1/687996710.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/2b/65/a1/687996710.webp"]', 30, 'semidetachedHouse', 'villa', 62.0, 61.0, 15.0, 100.0, 82.0, 50.0, 65.0, 980.0, 'Torino (TRN)', 17.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (114, '34042190', 230000.0, 261.0, 6, 1, 'Villa in strada Vicinale Ponte no number', 'Nestled on a gentle hill in Salento, in Parabita, near Gallipoli, this charming villa enjoys an exclusive and elevated position, overlooking three streets and offering a breathtaking view that embraces both the Ionian Sea and the lush surrounding countryside. The land, of approximately 5000 square meters, is a true corner of paradise, embellished with fruit trees, olive trees, and evergreens, surrounded by a typical dry stone wall that ensures privacy and rustic beauty. Thanks to the two driveway entrances, access is practical and convenient from the two main sides of the property. The heart of the villa develops on a raised ground floor of 75 square meters, furnished and habitable, which overlooks terraces and a balcony for a total of 100 square meters. The level terrace is surrounded by pillars that can be used to create a large pergola where you can relax, sipping an aperitif while admiring the sunset over the sea. Inside, a welcoming living area with kitchenette, hallway, two bedrooms, and a full bathroom. An internal staircase connects the living floor with a large basement of 180 square meters in its raw state, with large windows, perfect for being customized and transformed into additional living or recreational spaces, complete with predispositions and systems. Access is also possible via a convenient driveway ramp. An accessible cavity protects the contour of the structure from humidity. There is even an elevator room that will connect the two floors mentioned above and the roof terrace. The latter, accessible by a comfortable external staircase, will give you a view that spans between sky and earth, for an authentically Salento experience. There is no shortage of essential services such as an artesian well that provides pure water from a depth of 190 meters and a water storage tank; possibility of reactivating the alarm and automatic gate. Strategically located, just minutes from the beautiful beaches of Gallipoli and neighboring towns, this property repre', 'Matino', 'Lecce', 'puglia', 'strada Vicinale Ponte no number', 40.019173, 18.1198306, 'https://www.idealista.it/immobile/34042190/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/83/70/11/739389706.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/83/70/11/739389706.webp"]', 76, 'villa', 'villa', 61.0, 77.0, 40.0, 20.0, 60.0, 55.0, 74.0, 881.0, 'Bari (BRI)', 169.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (115, '26700712', 130000.0, 151.0, 5, 1, 'Villa in via Carlo Forlanini, 21', 'Just a stone''s throw from Torre Inserraglio, only 200 metres from the crystal-clear sea, the Grimaldi real estate agency in Nardò exclusively offers a wonderful solution with an already approved renovation project, complete with garage and free solar area. This magnificent small villa, of ample size, is currently composed of a large living room, a kitchenette, no less than four bedrooms and a bathroom. A garage and a large garden make this solution truly complete and allow several cars to be parked without any difficulty. The renovation includes the extension of the living area, with the creation of a large living-dining room, a sitting room, two bedrooms, one of which has an en-suite bathroom, a second bathroom and a storage room. The property is, of course, perfectly in order from an urban and cadastral point of view and can be purchased with a mortgage. Less than a 250-metre walk from the crystal-clear sea of Torre Inserraglio, it is an opportunity to be seized! Ideal for spending your holidays in absolute relaxation but also to be put to income guaranteeing a high annual yield, it can comfortably accommodate at least six people. A solution, therefore, more unique than rare. Don''t waste any more time, call us now to make an appointment! Grimaldi Immobiliare Nardò - Porto Cesareo Corso G. Galliano, 6/A - 73048 - Nardò (LE).', 'Nardò', 'Lecce', 'puglia', 'via Carlo Forlanini, 21', 40.182628, 17.9308664, 'https://www.idealista.it/immobile/26700712/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/87/3d/fe/482888939.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/87/3d/fe/482888939.webp"]', 97, 'villa', 'torre', 61.0, 78.0, 40.0, 40.0, 60.0, 66.0, 63.0, 861.0, 'Bari (BRI)', 145.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
INSERT INTO properties (id, external_id, price, size, rooms, bathrooms, title, description, town, province, region, address, latitude, longitude, url, lead_photo, photos, photos_count, raw_type, property_type, composite_score, value_score, sea_score, airport_score, location_score, character_score, social_potential_score, price_per_sqm, nearest_airport, airport_distance_km, distance_to_sea_km, status, batch_date, created_at, updated_at) VALUES (116, '34377953', 319000.0, 100.0, 5, 2, 'Detached house in via Cattedrale no number', 'The most spectacular sea-view palazzotto with Jacuzzi in the historic center of the White City Key Features: -Approx. 100 sqm of interior space, finished with premium materials -Independent luxury palazzotto in the historic center of Ostuni -Private pool and panoramic rooftop terrace with sea-view Jacuzzi -2 bedrooms: one with private hydromassage tub, one with natural stone bathroom -2 modern bathrooms, bright dining area -Fully equipped kitchen and panoramic balcony overlooking the sea and hills -Comfortable outdoor spaces with views of the countryside, the sea, and the White City -Air conditioning throughout -Perfect as a private residence or luxury B&B/holiday home In the vibrant heart of Ostuni, just steps from the iconic alleys of the historic center and only 2 minutes on foot from the renowned Piazza della Libertà, rises Ostuni Royal Terrace, an independent luxury residence designed for those seeking an authentic, exclusive, and unforgettable Mediterranean experience. The crystalline beaches of the Adriatic coast are reachable in 10–12 minutes by car, while Brindisi Airport is just 35 minutes away, making this property an exceptional retreat for international buyers searching for the perfect balance of historic charm, privacy, and contemporary comfort. The palazzotto unfolds with rare scenic elegance: luminous spaces, natural materials, and a constant dialogue between traditional Apulian architecture and subtle Greek-inspired atmospheres, where brilliant white tones meet the deep blue of the sea. Every detail has been curated to offer refined aesthetics and flawless functionality, creating a residence that feels straight out of the pages of a luxury design magazine. The two bedrooms, each crafted with unique design sensibilities, offer a captivating sensory experience: one suite opens onto a private hydromassage bathtub, ideal for wellness rituals bathed in Mediterranean light, while the other features a bathroom carved into the stone, a tribute to the millen', 'Ostuni', 'Brindisi', 'puglia', 'via Cattedrale no number', 40.7332504, 17.5785873, 'https://www.idealista.it/immobile/34377953/', 'https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/87/4b/68/752300109.webp', '["https://img4.idealista.it/blur/480_360_mq/0/id.pro.it.image.master/87/4b/68/752300109.webp"]', 52, 'independantHouse', 'palazzo', 61.0, 0.0, 40.0, 60.0, 92.0, 72.0, 89.0, 3190.0, 'Bari (BRI)', 82.0, NULL, 'qualified', '2026-03-12', '2026-03-12 17:35:14', '2026-03-12 17:35:14');
